window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[6]=[{"id":102600101,"themeId":6,"group":1026001,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении транспортных средств без установленных в предусмотренных местах регистрационных знаков (временных номерных знаков)?","a":["Разрешается, если регистрационный знак (временный номерной знак) повреждён, при его наличии в автомобиле.","Разрешается, если место крепления повреждено, при наличии регистрационного знака (временного номерного знака) в (на) автомобиле в месте, где он будет виден другим участникам дорожного движения.","Разрешается в обоих перечисленных случаях.","Запрещается."],"c":3,"e":"<p>Регистрационный знак является признаком государственной регистрации транспортного средства и служит свидетельством официального разрешения на участие в дорожном движении этого ТС.<br> При отсутствии в установленных местах хотя бы одного регистрационного знака участвовать в дорожном движении запрещено.</p>","image":"assets/adrive-questions/q102600101.webp"},{"id":102600102,"themeId":6,"group":1026001,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении транспортных средств без установленных в предусмотренных местах регистрационных знаков (временных номерных знаков)?","a":["Разрешается в период проведения регистрационных действий, порядок которых определён Советом Министров Республики Беларусь.","Разрешается при движении по дорогам местного значения без усовершенствованного покрытия.","Запрещается."],"c":2,"e":"<p>Регистрационный знак является признаком государственной регистрации транспортного средства и служит свидетельством официального разрешения на участие в дорожном движении этого ТС.<br> При отсутствии в установленных местах хотя бы одного регистрационного знака участвовать в дорожном движении запрещено.</p>","image":"assets/adrive-questions/q102600102.webp"},{"id":102600201,"themeId":6,"group":1026002,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев разрешается участие в дорожном движении транспортного средства с правосторонним расположением органов управления?","a":["Если транспортным средством управляет лицо, временно прибывшее в Республику Беларусь.","Если транспортное средство принадлежит лицу, временно прибывшему в Республику Беларусь.","Если транспортным средством управляет лицо, не являющееся гражданином Республики Беларусь.","Запрещается во всех перечисленных случаях."],"c":1,"e":"<p>Правила дорожного движения запрещают участвовать в дорожном движении на территории Республики Беларусь ТС с правосторонним расположением органов управления. Исключение сделано лишь для ТС, которые были зарегистрированы ГАИ до вступления в силу Закона (до 10 августа 2002 года), а также принадлежащим лицам, временно прибывшим в Республику Беларусь.</p>","image":"assets/adrive-questions/q102600201.webp"},{"id":102600202,"themeId":6,"group":1026002,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев разрешается участие в дорожном движении транспортного средства с правосторонним расположением органов управления?","a":["Если транспортное средство ввезено на территорию Республики Беларусь до 10 августа 2002 года.","Если транспортное средство приобретено на территории Республики Беларусь до 10 августа 2002 года.","Если транспортное средство зарегистрировано на территории Республики Беларусь до 10 августа 2002 года.","Запрещается во всех перечисленных случаях."],"c":2,"e":"<p>Правила дорожного движения запрещают участвовать в дорожном движении на территории Республики Беларусь ТС с правосторонним расположением органов управления. Исключение сделано лишь для ТС, которые были зарегистрированы ГАИ до вступления в силу Закона (до 10 августа 2002 года), а также принадлежащим лицам, временно прибывшим в Республику Беларусь.</p>","image":"assets/adrive-questions/q102600202.webp"},{"id":102600301,"themeId":6,"group":1026003,"chapter":26,"chapters":[26],"q":"Разрешается ли переоборудовать транспортное средство путём изменения его назначения, предусмотренного документацией изготовителя?","a":["Нет, не разрешается.","Разрешается по согласованию с ГАИ в порядке, установленном Министерством внутренних дел."],"c":1,"e":"<p>Порядок переоборудования согласовывается в соответствии с постановлением МВД от 30.06.2006 № 177 «Об утверждении Инструкции о порядке деятельности подразделений технического надзора государственной автомобильной инспекции Министерства внутренних дел Республики Беларусь», а в части оборудования маячками, специальными звуковыми сигналами — постановлением МВД от 04.04.2008 № 103 «Об утверждении Инструкции о порядке оборудования проблесковыми сигналами (маячками) и специальными звуковыми сигналами транспортных средств, самоходных машин».</p>","image":"assets/adrive-questions/q102600301.webp"},{"id":102600302,"themeId":6,"group":1026003,"chapter":26,"chapters":[26],"q":"Разрешается ли переоборудовать транспортное средство без согласования с ГАИ?","a":["Нет, не разрешается.","Разрешается без изменения его типа и (или) назначения, а также весовых, габаритных или иных технических характеристик, предусмотренных документацией изготовителя."],"c":1,"e":"<p>Порядок переоборудования согласовывается в соответствии с постановлением МВД от 30.06.2006 № 177 «Об утверждении Инструкции о порядке деятельности подразделений технического надзора государственной автомобильной инспекции Министерства внутренних дел Республики Беларусь», а в части оборудования маячками, специальными звуковыми сигналами — постановлением МВД от 04.04.2008 № 103 «Об утверждении Инструкции о порядке оборудования проблесковыми сигналами (маячками) и специальными звуковыми сигналами транспортных средств, самоходных машин».</p>","image":"assets/adrive-questions/q102600302.webp"},{"id":102600401,"themeId":6,"group":1026004,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении транспортных средств, не зарегистрированных в порядке, установленном Советом Министров Республики Беларусь?","a":["Нет, не разрешается.","Разрешается участие в дорожном движении прицепов к колёсным тракторам при следовании к месту проведения сельхозработ.","Разрешается участие в дорожном движении транспортных средств, изготовленных самостоятельно (не в заводских условиях)."],"c":0,"e":"<p>Порядок регистрации транспортных средств установлен «Положением о порядке государственной регистрации и государственного учёта транспортных средств, снятия с учёта и внесения изменений в документы, связанные с регистрацией транспортных средств», которое утверждено Постановлением Совета Министров Республики Беларусь от 31.12.2002 № 1849.</p>","image":"assets/adrive-questions/q102600401.webp"},{"id":102600402,"themeId":6,"group":1026004,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении транспортных средств, не зарегистрированных в порядке, установленном Советом Министров Республики Беларусь?","a":["Нет, не разрешается.","Разрешается только при включении аварийной световой сигнализации.","Разрешается только по дорогам с малой интенсивностью движения вне населённых пунктов."],"c":0,"e":"<p>Порядок регистрации транспортных средств установлен «Положением о порядке государственной регистрации и государственного учёта транспортных средств, снятия с учёта и внесения изменений в документы, связанные с регистрацией транспортных средств», которое утверждено Постановлением Совета Министров Республики Беларусь от 31.12.2002 № 1849.</p>","image":"assets/adrive-questions/q102600402.webp"},{"id":102600531,"themeId":6,"group":1026005,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев допускается участие в дорожном движении транспортного средства, не имеющего разрешения на его допуск к участию в дорожном движении?","a":["В случае, если срок получения разрешения на его допуск к участию в дорожном движении истёк не более 10 дней назад.","В случае отсутствия владельца транспортного средства в Республике Беларусь.","Не допускается в любом случае."],"c":2,"e":"<p>Владельцы (пользователи) транспортных средств, участвующих в дорожном движении, обязаны своевременно получать разрешение на его допуск к участию в дорожном движении.<br> Водители, участвующие в дорожном движении на транспортных средствах, не имеющих разрешения на его допуск к участию в дорожном движении, несут ответственность в соответствии с действующим законодательством Республики Беларусь.</p>","image":"assets/adrive-questions/q102600531.webp"},{"id":102600532,"themeId":6,"group":1026005,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев допускается участие в дорожном движении транспортных средств, не имеющих разрешения на допуск к участию в дорожном движении?","a":["Допускается буксировка прицепов, не оборудованных тормозной системой, при движении по дорогам без усовершенствованного покрытия.","Допускается участие в дорожном движении мопедов и мотоциклов при движении по дорогам без усовершенствованного покрытия.","Не допускается в любом случае."],"c":2,"e":"<p>Владельцы транспортных средств, участвующих в дорожном движении, обязаны своевременно получать разрешение на его допуск к участию в дорожном движении.<br> Водители, участвующие в дорожном движении на транспортных средствах, не имеющих разрешения на его допуск к участию в дорожном движении, несут ответственность в соответствии с действующим законодательством Республики Беларусь.</p>","image":"assets/adrive-questions/q102600532.webp"},{"id":102600801,"themeId":6,"group":1026008,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении во время выпадения осадков транспортного средства с неисправными стеклоочистителями?","a":["Нет, не разрешается.","Разрешается, если исправны стеклоомыватели.","Разрешается при выпадении неинтенсивных осадков."],"c":0,"e":"<p>Если не работают стеклоочистители во время выпадения осадков, водитель должен прекратить движение, принять меры к устранению неисправности. Если устранить неисправности не удалось, то для доставки неисправного ТС к месту ремонта или стоянки можно воспользоваться специализированной технической помощью либо отбуксировать ТС с соблюдением действующих Правил дорожного движения или подождать, пока не закончатся осадки, а затем — следовать к месту стоянки или ремонта.</p>","image":"assets/adrive-questions/q102600801.webp"},{"id":102600802,"themeId":6,"group":1026008,"chapter":26,"chapters":[26],"q":"При наличии какой из перечисленных неисправностей запрещается участие в дорожном движении транспортных средств?","a":["С неисправной рабочей тормозной системой.","С неисправным сцепным устройством (в составе автопоезда).","С негорящими фарами при недостаточной видимости дороги.","При наличии любой из перечисленных неисправностей."],"c":3,"e":"<p>При неисправности рабочей тормозной системы водителю запрещено продолжать движение. Если устранить неисправность не возможно, то он должен доставить ТС к месту стоянки или ремонта путём буксировки с учётом требований Правил дорожного движения или путём полной погрузки. При возникновении неисправностей в сцепном устройстве автопоезда водитель должен прекратить дальнейшее движение и принять меры к их устранению, а если это невозможно, то доставить прицеп к месту стоянки или ремонта с помощью специализированной технической службы. Движение с негорящими фарами в условиях недостаточной видимости дороги очень опасно, так как не позволяет водителю хорошо ориентироваться, что может явиться причиной столкновения ТС или наезда даже на обозначенное в соответствии с требованиями Правил дорожного движения неподвижное препятствие или пешехода.</p>","image":null},{"id":102600901,"themeId":6,"group":1026009,"chapter":26,"chapters":[26],"q":"Какая минимальная степень светопропускания допускается для ветрового стекла, при которой не запрещается участие в дорожном движении транспортного средства?","a":["85 процентов.","80 процентов.","75 процентов.","70 процентов.","60 процентов."],"c":3,"e":"<p>Разрешается участие в дорожном движении транспортного средства, если степень светопропускания ветрового стекла составляет не менее 70 процентов.</p>","image":"assets/adrive-questions/q102600901.webp"},{"id":102600902,"themeId":6,"group":1026009,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если степень светопропускания его ветрового стекла составляет 79 процентов?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Разрешается участие в дорожном движении транспортного средства, если степень светопропускания ветрового стекла составляет не менее 70 процентов.</p>","image":"assets/adrive-questions/q102600902.webp"},{"id":102601001,"themeId":6,"group":1026010,"chapter":26,"chapters":[26],"q":"Какая минимальная степень светопропускания допускается для передних боковых стёкол, при которой не запрещается участие в дорожном движении транспортного средства?","a":["85 процентов.","80 процентов.","75 процентов.","70 процентов.","60 процентов."],"c":3,"e":"<p>Разрешается участие в дорожном движении транспортного средства, если степень светопропускания передних боковых стёкол составляет не менее 70 процентов.</p>","image":"assets/adrive-questions/q102601001.webp"},{"id":102601002,"themeId":6,"group":1026010,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если степень светопропускания его передних боковых стёкол составляет 69 процентов?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Разрешается участие в дорожном движении транспортного средства, если степень светопропускания передних боковых стёкол составляет не менее 70 процентов.</p>","image":"assets/adrive-questions/q102601002.webp"},{"id":102601101,"themeId":6,"group":1026011,"chapter":26,"chapters":[26],"q":"Разрешается ли участие в дорожном движении транспортного средства с внешне видимыми наклейками (изображениями)?","a":["Нет, не разрешается.","Разрешается, если они не закрывают внешние световые приборы и световозвращатели.","Разрешается, если они не ухудшают светопропускание в салон автомобиля и не ограничивают обзорности.","Разрешается, если они содержат информацию о принадлежности транспортного средства индивидуальному предпринимателю."],"c":3,"e":"<p>Участие в дорожном движении транспортного средства с внешне видимыми наклейками (изображениями) не запрещается, если они содержат информацию о принадлежности транспортного средства индивидуальному предпринимателю.</p>","image":null},{"id":102601102,"themeId":6,"group":1026011,"chapter":26,"chapters":[26],"q":"Какие внешне видимые наклейки (изображения) не разрешается размещать на транспортном средстве?","a":["Рекламу.","Опознавательные знаки транспортного средства.","Информацию о принадлежности транспортного средства соответствующей организации (индивидуальному предпринимателю).","Разрешается размещать всё перечисленное в установленном порядке."],"c":3,"e":"<p>Участие в дорожном движении транспортного средства с внешне видимыми наклейками (изображениями) разрешается, если они содержат информацию о принадлежности транспортного средства индивидуальному предпринимателю.</p> <p>Также разрешается размещать рекламу и опознавательные знаки транспортного средства.</p>","image":null},{"id":102601202,"themeId":6,"group":1026012,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев не запрещается участие в дорожном движении транспортного средства?","a":["При наличии неисправности, не указанной в Правилах дорожного движения.","Если степень светопропускания ветрового стекла составляет 76%.","Если на транспортном средстве размещена информация о принадлежности транспортного средства соответствующей организации.","Участие в дорожном движении разрешается во всех перечисленных случаях."],"c":3,"e":"<p>Участие в дорожном движении не запрещается, если на транспортном средстве размещена информация о принадлежности транспортного средства соответствующей организации, степень светопропускания ветрового стекла составляет не менее 70%, а также при наличии неисправности, не указанной в Правилах дорожного движения (приложение 4 к ПДД).</p>","image":null},{"id":102601231,"themeId":6,"group":1026012,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев не запрещается участие в дорожном движении транспортного средства?","a":["Если степень светопропускания передних боковых стёкол составляет 72%.","Если не горят задние габаритные огни в тёмное время суток.","Если на транспортном средстве размещён опознавательный знак, отличающийся от знака установленного образца.","Участие в дорожном движении запрещается во всех перечисленных случаях."],"c":0,"e":"<p>Разрешается участие в дорожном движении транспортного средства, если степень светопропускания передних боковых стёкол составляет не менее 70 процентов.</p>","image":null},{"id":102601301,"themeId":6,"group":1026013,"chapter":26,"chapters":[26],"q":"Как должен поступить водитель, если во время выпадения осадков в виде снега не работают стеклоочистители, а устранить неисправность на месте невозможно?","a":["Прекратить дальнейшее движение.","Продолжить движение, включив обогрев и обдув стёкол на максимальную мощность.","Двигаться к месту стоянки или ремонта, периодически останавливаясь для очистки ветрового стекла."],"c":0,"e":"<p>Если не работают стеклоочистители во время выпадения осадков, водитель должен прекратить движение, принять меры к устранению неисправности. Если устранить неисправности не удалось, то для доставки неисправного ТС к месту ремонта или стоянки можно воспользоваться специализированной технической помощью либо отбуксировать ТС с соблюдением действующих Правил дорожного движения или подождать, пока не закончатся осадки, а затем — следовать к месту стоянки или ремонта.</p>","image":"assets/adrive-questions/q102601301.webp"},{"id":102601302,"themeId":6,"group":1026013,"chapter":26,"chapters":[26],"q":"Как должен поступить водитель, если при движении к месту ремонта в светлое время суток с негорящими (отсутствующими) фарами он попал в полосу сильного тумана и видимость дороги снизилась до 200–250 метров?","a":["Прекратить дальнейшее движение.","Продолжить движение, увеличив скорость, чтобы быстрее проехать опасный участок.","Продолжить движение, снизив скорость, с включённой аварийной световой сигнализацией."],"c":0,"e":"<p>Движение без света в фарах в условиях недостаточной видимости дороги очень опасно, так как не позволяет водителю хорошо ориентироваться, что может явиться причиной столкновения ТС или наезда даже на обозначенное в соответствии с требованиями Правил дорожного движения неподвижное препятствие или пешехода. Поэтому водителю в данной ситуации необходимо прекратить дальнейшее движение.</p>","image":"assets/adrive-questions/q102601302.webp"},{"id":102601361,"themeId":6,"group":1026013,"chapter":26,"chapters":[26],"q":"Как следует поступить водителю, если во время небольшого дождя не работают стеклоочистители ветрового стекла, а устранить неисправность нет возможности?","a":["Продолжить намеченную поездку с особой осторожностью.","Остановиться и не возобновлять движение до прекращения дождя.","Следовать к месту стоянки или ремонта, включив аварийную световую сигнализацию, соблюдая необходимые меры предосторожности по обеспечению безопасности дорожного движения."],"c":1,"e":"<p><strong>Запрещается</strong> осуществлять движение <strong>при неработающих стеклоочистителях</strong> ветрового стекла <strong>во время выпадения осадков</strong>.</p>","image":"assets/adrive-questions/q102601361.webp"},{"id":102601402,"themeId":6,"group":1026014,"chapter":26,"chapters":[26],"q":"Как должен поступить водитель, если во время движения перестала действовать рабочая тормозная система, а устранить эту неисправность на месте невозможно?","a":["Прекратить дальнейшее движение.","Продолжить движение только к месту стоянки или ремонта, включив аварийную световую сигнализацию, на минимальной скорости, затормаживая автомобиль двигателем и стояночным тормозом."],"c":0,"e":"<p>При неисправности рабочей тормозной системы водителю запрещено движение до устранения неисправности. Если это невозможно, то он должен доставить ТС к месту стоянки или ремонта путём буксировки с учётом требований Правил дорожного движения или путём полной погрузки.</p>","image":"assets/adrive-questions/q102601402.webp"},{"id":102601431,"themeId":6,"group":1026014,"chapter":26,"chapters":[26],"q":"Как должен поступить водитель, если во время движения на значительное расстояние к месту ремонта на автомобиле с негорящим фарами наступило тёмное время суток?","a":["Прекратить дальнейшее движение.","Продолжить движение, если участок дороги имеет искусственное освещение.","Продолжить движение вслед за попутно движущимся транспортным средством на небольшой дистанции от него."],"c":0,"e":"<p>Движение без света в фарах в тёмное время суток (даже по освещённому участку дороги) очень опасно, так как не позволяет водителю хорошо ориентироваться, что может явиться причиной столкновения транспортных средств или наезда даже на обозначенное в соответствии с требованиями Правил дорожного движения неподвижное препятствие или пешехода. Кроме того, автомобиль плохо виден со встречного направления.</p> <p>Поэтому водителю в данной ситуации необходимо прекратить дальнейшее движение.</p>","image":"assets/adrive-questions/q102601431.webp"},{"id":102601601,"themeId":6,"group":1026016,"chapter":26,"chapters":[26],"q":"При наличии какой неисправности транспортного средства запрещается самостоятельное следование к месту стоянки или ремонта с соблюдением необходимых мер предосторожности?","a":["Отсутствует ветровое стекло.","Негерметична система смазки двигателя.","Неисправно сцепное устройство (в составе автопоезда).","Негерметична газовая топливная система на автомобиле с газовой топливной аппаратурой."],"c":2,"e":"<p>При возникновении неисправностей в сцепном устройстве автопоезда водитель должен принять меры к их устранению, а если это невозможно, то доставить прицеп к месту стоянки или ремонта с помощью специализированной технической службы.</p>","image":null},{"id":102601602,"themeId":6,"group":1026016,"chapter":26,"chapters":[26],"q":"При наличии какой неисправности транспортного средства запрещается самостоятельное следование к месту стоянки или ремонта с соблюдением необходимых мер предосторожности?","a":["Неисправен звуковой сигнал.","Неисправна система охлаждения двигателя.","Не работают стеклоомыватели (во время выпадения осадков).","Не работают стеклоочистители (во время выпадения осадков)."],"c":3,"e":"<p>Если не работают стеклоочистители во время выпадения осадков, водитель должен прекратить движение, принять меры к устранению неисправности. Если устранить неисправности не удалось, то для доставки неисправного ТС к месту ремонта или стоянки можно воспользоваться специализированной технической помощью либо отбуксировать ТС с соблюдением действующих Правил дорожного движения или подождать, пока не закончатся осадки, а затем — следовать к месту стоянки или ремонта.</p>","image":null},{"id":102601701,"themeId":6,"group":1026017,"chapter":26,"chapters":[26],"q":"Как должен поступить водитель, если во время движения с прицепом он обнаружил неисправность сцепного устройства, а устранить эту неисправность на месте невозможно?","a":["Прекратить дальнейшее движение.","Продолжить движение к месту стоянки или ремонта, включив аварийную световую сигнализацию.","Продолжить движение к месту стоянки или ремонта, дополнительно закрепив крепление прицепа с помощью страховочных тросов или цепей."],"c":0,"e":"<p>При возникновении неисправностей в сцепном устройстве автопоезда водитель должен прекратить дальнейшее движение и принять меры к их устранению, а если это невозможно, то доставить прицеп к месту стоянки или ремонта с помощью специализированной технической службы.</p>","image":"assets/adrive-questions/q102601701.webp"},{"id":102601702,"themeId":6,"group":1026017,"chapter":26,"chapters":[26],"q":"При наличии какой из перечисленных неисправностей прицепа запрещено осуществлять его буксировку даже к месту ремонта?","a":["Неисправно сцепное устройство.","Не работают сигналы торможения.","Отсутствуют два болта крепления колеса.","Не работают световые указатели поворотов."],"c":0,"e":"<p>При возникновении неисправностей в сцепном устройстве автопоезда водитель должен принять меры к их устранению, а если это невозможно, то доставить прицеп к месту стоянки или ремонта с помощью специализированной технической службы.</p>","image":"assets/adrive-questions/q102601702.webp"},{"id":102601801,"themeId":6,"group":1026018,"chapter":26,"chapters":[26],"q":"При какой неисправности из перечисленных, если устранить её невозможно, водителю запрещается продолжать движение, в том числе к месту стоянки или ремонта?","a":["Негерметична система питания.","Не горят сигналы торможения на прицепе.","Неисправна стояночная тормозная система.","Неисправны стеклоочистители во время небольшого дождя."],"c":3,"e":"<p>Если не работают стеклоочистители во время выпадения осадков, водитель должен прекратить движение, принять меры к устранению неисправности. Если устранить неисправности не удалось, то для доставки неисправного ТС к месту ремонта или стоянки можно воспользоваться специализированной технической помощью либо отбуксировать ТС с соблюдением действующих Правил дорожного движения или подождать, пока не закончатся осадки, а затем — следовать к месту стоянки или ремонта.</p>","image":null},{"id":102601802,"themeId":6,"group":1026018,"chapter":26,"chapters":[26],"q":"При какой неисправности из перечисленных, если устранить её невозможно, водителю запрещается продолжать движение, в том числе к месту стоянки или ремонта?","a":["Негерметична система смазки двигателя.","Неисправны стеклоочистители в тёмное время суток.","Неисправны стеклоомыватели во время выпадения осадков.","Не горят задние габаритные огни в условиях недостаточной видимости."],"c":3,"e":"<p>Движение с негорящими задними габаритными огнями в условиях недостаточной видимости по дороге очень опасно, так как не позволяет водителям движущихся сзади попутных транспортных средств своевременно обнаружить движущееся впереди транспортное средство, что может явиться причиной попутного столкновения. Поэтому водителю в данной ситуации необходимо прекратить дальнейшее движение.</p>","image":null},{"id":102602001,"themeId":6,"group":1026020,"chapter":26,"chapters":[26],"q":"При какой неисправности из перечисленных, если устранить её невозможно, водителю запрещается продолжать движение, в том числе к месту стоянки или ремонта?","a":["Неисправна система выпуска отработавших газов.","Не работает устройство обогрева и обдува в зимнее время.","Негерметична газовая система питания на транспортном средстве с газовой топливной аппаратурой.","Неисправно рулевое управление на автомобиле, оборудованном гидроусилителем рулевого управления."],"c":3,"e":"<p>При неисправности рулевого управления водителю запрещено движение. Если устранить неисправность невозможно, то он должен доставить ТС к месту стоянки или ремонта только путём полной или частичной погрузки на другое ТС.</p>","image":null},{"id":102602002,"themeId":6,"group":1026020,"chapter":26,"chapters":[26],"q":"При какой неисправности из перечисленных, если устранить её невозможно, водителю запрещается продолжать движение, в том числе к месту стоянки или ремонта?","a":["Неисправна рабочая тормозная система.","Неисправна стояночная тормозная система.","Негерметична система охлаждения двигателя.","Негерметичен гидравлический привод управления сцеплением.","Движение запрещено при любой из перечисленных неисправностей."],"c":0,"e":"<p>При неисправности рабочей тормозной системы водителю запрещено продолжать движение. Если устранить неисправность невозможно, то он должен доставить ТС к месту стоянки или ремонта путём буксировки с учётом требований Правил дорожного движения или путём полной погрузки.</p>","image":null},{"id":102602102,"themeId":6,"group":1026021,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев водитель выполнит требования Правил дорожного движения, если во время движения в светлое время суток при недостаточной видимости дороги погасли фары (не горит ни ближний, ни дальний свет), а устранить неисправность не представляется возможным?","a":["Прекратит дальнейшее движение.","Включит противотуманные фары и продолжит движение с особой осторожностью.","Включит аварийную световую сигнализацию и продолжит движение к месту стоянки или ремонта."],"c":0,"e":"<p>Движение с негорящими фарами в условиях недостаточной видимости дороги очень опасно, так как не позволяет водителю хорошо ориентироваться, что может явиться причиной столкновения ТС или наезда даже на обозначенное в соответствии с требованиями Правил дорожного движения неподвижное препятствие или пешехода. Поэтому водителю в данной ситуации необходимо прекратить дальнейшее движение.</p>","image":"assets/adrive-questions/q102602102.webp"},{"id":102602131,"themeId":6,"group":1026021,"chapter":26,"chapters":[26],"q":"В каком из перечисленных случаев водитель выполнит требования Правил дорожного движения, если во время движения в тёмное время суток на освещённом участке дороги погасли фары (не горит ни ближний, ни дальний свет), а устранить неисправность не представляется возможным?","a":["Прекратит дальнейшее движение.","Включит противотуманные фары и продолжит движение с особой осторожностью.","Включит аварийную световую сигнализацию и продолжит движение к месту стоянки или ремонта."],"c":0,"e":"<p>Движение с негорящими фарами в тёмное время суток (даже по освещённому участку дороги) очень опасно, так как не позволяет водителю хорошо ориентироваться, что может явиться причиной столкновения ТС или наезда даже на обозначенное в соответствии с требованиями Правил дорожного движения неподвижное препятствие или пешехода. Кроме того, автомобиль плохо виден со встречного направления. Поэтому водителю в данной ситуации необходимо прекратить дальнейшее движение.</p>","image":"assets/adrive-questions/q102602131.webp"},{"id":102602241,"themeId":6,"group":1026022,"chapter":26,"chapters":[26],"q":"Средство персональной мобильности должно иметь:","a":["Исправные тормозную систему и рулевое управление (при наличии).","Исправные тормозную систему и рулевое управление (при наличии) и звуковой сигнал."],"c":1,"e":"<p>Средство персональной мобильности должно иметь исправные <strong>тормозную систему, рулевое управление (при наличии) и звуковой сигнал</strong>.</p>","image":null},{"id":102602301,"themeId":6,"group":1026023,"chapter":26,"chapters":[26],"q":"Требуется ли установка на легковом автомобиле опознавательного знака «Автопоезд» при его движении с прицепом?","a":["Нет, не требуется.","Требуется, если прицеп имеет две оси."],"c":0,"e":"<p>Опознавательный знак «Автопоезд» устанавливается на грузовых автомобилях и колёсных тракторах (классов тяги 1.4 тонны и выше) с прицепами, на сочленённых автобусах и троллейбусах.</p> <p>Установка на легковом автомобиле с прицепом опознавательного знака «Автопоезд» не требуется.</p>","image":"assets/adrive-questions/q102602301.webp"},{"id":102602302,"themeId":6,"group":1026023,"chapter":26,"chapters":[26],"q":"Требуется ли установка на автомобиле категории «В» опознавательного знака «Автопоезд» при его движении с прицепом?","a":["Нет, не требуется.","Требуется на легковых и грузовых автомобилях при буксировке двухосного прицепа.","Требуется на грузовых автомобилях с технически допустимой общей массой не более 3.5 тонны."],"c":2,"e":"<p>Опознавательный знак «Автопоезд» устанавливается на всех грузовых автомобилях и колёсных тракторах (классов тяги 1.4 тонны и выше) с прицепами, а также на сочленённых автобусах и троллейбусах.</p>","image":null},{"id":102602351,"themeId":6,"group":1026023,"chapter":26,"chapters":[26],"q":"Что означают три включённых оранжевых фонаря на крыше кабины грузового автомобиля?","a":["Автомобиль имеет большую длину.","Автомобиль движется с прицепом.","Автомобиль перевозит опасные грузы.","Автомобиль имеет большую грузоподъёмность.","Автомобиль движется в организованной транспортной колонне."],"c":1,"e":"<p>Три оранжевых фонаря на крыше кабины грузового автомобиля означают, что <strong>автомобиль буксирует прицеп</strong>, полуприцеп или прицеп-роспуск.</p>","image":"assets/adrive-questions/q102602351.webp"},{"id":102602601,"themeId":6,"group":1026026,"chapter":26,"chapters":[26],"q":"Где на механическом транспортном средстве, имеющем ошипованные шины, может быть закреплён показанный на рисунке опознавательный знак?","a":["Только сзади механического транспортного средства.","Только спереди механического транспортного средства.","Спереди и сзади механического транспортного средства."],"c":0,"e":"<p>Опознавательный знак «Шипы» может использоваться на механических транспортных средствах, имеющих ошипованные шины, и устанавливается сзади таких транспортных средств.</p>","image":"assets/adrive-questions/q102602601.webp"},{"id":102602632,"themeId":6,"group":1026026,"chapter":26,"chapters":[26],"q":"Должен ли водитель механического транспортного средства, имеющего ошипованные шины, в обязательном порядке закрепить на нём опознавательный знак «Шипы»?","a":["Да, должен.","По желанию водителя."],"c":1,"e":"<p>Опознавательный знак «Шипы» может использоваться на механических транспортных средствах, имеющих ошипованные шины, и устанавливается сзади транспортного средства.</p> <p>Для предупреждения попутного столкновения на обледеневших и заснеженных дорогах водители транспортных средств, движущихся сзади, должны выбирать безопасную дистанцию до впереди движущегося механического транспортного средства с ошипованными шинами.</p>","image":"assets/adrive-questions/q102602632.webp"},{"id":102602731,"themeId":6,"group":1026027,"chapter":26,"chapters":[26],"q":"На каких транспортных средствах должен использоваться показанный на рисунке опознавательный знак?","a":["На механических транспортных средствах, управляемых водителями с водительским стажем менее двух лет.","На механических транспортных средствах, используемых для обучения управлению механическим транспортным средством, приема квалификационного практического экзамена на право управления транспортным средством.","На механических транспортных средствах, используемых для обучения управлению механическим транспортным средством и (или) управляемых водителями с водительским стажем менее двух лет."],"c":1,"e":"<p>Опознавательный знак «Учебное транспортное средство» должен использоваться на механических транспортных средствах, используемых для обучения управлению механическим транспортным средством, приема квалификационного практического экзамена на право управления транспортным средством.</p>","image":"assets/adrive-questions/q102602731.webp"},{"id":102602732,"themeId":6,"group":1026027,"chapter":26,"chapters":[26],"q":"На каких механических транспортных средствах устанавливается показанный на рисунке двусторонний светящийся знак?","a":["На крыше автобусов, используемых для обучения управлению механическим транспортным средством.","На крыше грузовых автомобилей, используемых для обучения управлению механическим транспортным средством.","На крыше легковых автомобилей, используемых для обучения управлению механическим транспортным средством, приема квалификационного практического экзамена на право управления транспортным средством.","На всех перечисленных транспортных средствах."],"c":2,"e":"<p>Двусторонний светящийся опознавательный знак «Учебное транспортное средство» должен использоваться на крыше легковых автомобилей, используемых для обучения управлению механическим транспортным средством, приема квалификационного практического экзамена на право управления транспортным средством.</p>","image":"assets/adrive-questions/q102602732.webp"},{"id":102602802,"themeId":6,"group":1026028,"chapter":26,"chapters":[26],"q":"Обязательно ли устанавливать на автомобиль опознавательный знак, показанный на рисунке, если у водителя водительский стаж менее двух лет?","a":["Да, обязательно.","Нет, необязательно, если у владельца автомобиля водительский стаж не менее двух лет."],"c":0,"e":"<p>Опознавательный знак устанавливается на механических транспортных средствах, управляемых водителями с водительским стажем менее 2 лет.</p>","image":"assets/adrive-questions/q102602802.webp"},{"id":102602901,"themeId":6,"group":1026029,"chapter":26,"chapters":[26],"q":"Должен ли водитель с водительским стажем менее двух лет устанавливать опознавательный знак, показанный на рисунке, на грузовой автомобиль с технически допустимой общей массой менее 3.5 тонны?","a":["Да, должен.","Нет, не должен."],"c":0,"e":"<p>Опознавательный знак устанавливается на механических транспортных средствах, управляемых водителями с водительским стажем менее 2 лет.</p>","image":"assets/adrive-questions/q102602901.webp"},{"id":102602902,"themeId":6,"group":1026029,"chapter":26,"chapters":[26],"q":"Должен ли водитель обозначить транспортное средство опознавательным знаком «Ограничение скорости», если вследствие неисправности транспортное средство не может развивать скорость более 50 км/ч?","a":["Должен только вне населённых пунктов.","Должен на всех дорогах, в том числе в населённых пунктах.","Не должен."],"c":2,"e":"<p>Водитель не обязан обозначать транспортное средство опознавательным знаком «Ограничение скорости» , если вследствие неисправности транспортное средство не может развивать скорость более 50 км/ч.</p>","image":"assets/adrive-questions/q102602902.webp"},{"id":102603001,"themeId":6,"group":1026030,"chapter":26,"chapters":[26],"q":"Как правильно установить на автомобиль опознавательный знак «Ограничение скорости»?","a":["На задней стороне кузова слева.","На задней стороне кузова справа.","На задней стороне кузова посередине."],"c":0,"e":"<p>Опознавательный знак «Ограничение скорости» устанавливается на задней стороне кузова слева.</p>","image":"assets/adrive-questions/q102603001.webp"},{"id":102603201,"themeId":6,"group":1026032,"chapter":26,"chapters":[26],"q":"На каких механических транспортных средствах требуется согласно Правилам дорожного движения устанавливать опознавательный знак «Ограничение скорости»?","a":["На транспортных средствах, перевозящих крупногабаритные грузы.","На грузовых автомобилях, перевозящих пассажиров в кузове с бортовой платформой или в кузове-фургоне.","На механических транспортных средствах, используемых для обучения управлению механическим транспортным средством.","На всех перечисленных транспортных средствах требуется установка данного опознавательного знака."],"c":0,"e":"<p>Опознавательный знак должен быть установлен на механических транспортных средствах, перевозящих крупногабаритные грузы.</p>","image":null},{"id":102603202,"themeId":6,"group":1026032,"chapter":26,"chapters":[26],"q":"На каких механических транспортных средствах не требуется согласно Правилам дорожного движения устанавливать опознавательный знак «Ограничение скорости»?","a":["На транспортных средствах, максимальная скорость которых ограничена условиями перевозки крупногабаритных грузов.","На транспортных средствах, которые по технической характеристике не могут развивать максимальную скорость, определённую Правилами дорожного движения.","На транспортных средствах, которые по техническому состоянию, обусловленному наличием неисправности, не могут развивать максимальную скорость, определённую Правилами дорожного движения.","На всех перечисленных транспортных средствах требуется установка данного опознавательного знака."],"c":2,"e":"<p>Опознавательный знак должен быть установлен на механических транспортных средствах, управляемых водителями с водительским стажем менее 2 лет, перевозящих опасные, тяжеловесные, крупногабаритные грузы, а также в случаях, когда максимальная скорость транспортного средства по технической характеристике (а не из-за его технического состояния) ниже скорости движения, определённой в пункте 89 Правил дорожного движения.</p>","image":null},{"id":102603301,"themeId":6,"group":1026033,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак, установленный на автобусе?","a":["Автобус перевозит группу детей.","Автобус принадлежит учреждению образования.","Автобус используется для перевозки экскурсий и туристических групп."],"c":0,"e":"<p>Опознавательный знак «Перевозка детей» , установленный на автобусе, означает, что автобус перевозит группу детей.</p>","image":"assets/adrive-questions/q102603301.webp"},{"id":102603302,"themeId":6,"group":1026033,"chapter":26,"chapters":[26],"q":"В каком случае водитель автобуса обязан обозначить его опознавательным знаком «Перевозка детей»?","a":["При перевозке групп детей.","При перевозке экскурсий и туристических групп.","При движении (в регулярном сообщении) по установленному маршруту с обозначенными остановочными пунктами, если в автобусе находятся дети."],"c":0,"e":"<p>При перевозке групп детей водитель автобуса обязан обозначить его опознавательным знаком «Перевозка детей» .</p>","image":"assets/adrive-questions/q102603302.webp"},{"id":102603401,"themeId":6,"group":1026034,"chapter":26,"chapters":[26],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, обозначив автомобиль при перевозке детей опознавательным знаком «Перевозка детей»?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>Опознавательный знак «Перевозка детей» устанавливается только на автобусах при перевозке групп детей и применяется для повышения безопасности перевозки такой категории пассажиров, как дети, путём предупреждения других водителей о необходимости проявления повышенного внимания по отношению к транспортному средству, на котором установлен этот опознавательный знак.</p> <p>На легковом автомобиле такой опознавательный знак не устанавливается.</p>","image":null},{"id":102603402,"themeId":6,"group":1026034,"chapter":26,"chapters":[26],"q":"Водители каких транспортных средств при перевозке группы детей должны обозначить своё транспортное средство опознавательным знаком «Перевозка детей»?","a":["Водители автобусов.","Водители троллейбусов.","Водители легковых автомобилей.","Водители автобусов и троллейбусов.","Водители всех перечисленных транспортных средств."],"c":0,"e":"<p>Опознавательный знак «Перевозка детей» устанавливается только на автобусах при перевозке групп детей и применяется для повышения безопасности перевозки такой категории пассажиров, как дети, путём предупреждения других водителей о необходимости проявления повышенного внимания по отношению к транспортному средству, на котором установлен этот опознавательный знак.</p>","image":null},{"id":102603501,"themeId":6,"group":1026035,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак, установленный на автобусе?","a":["Автобус движется по маршруту «К».","Автобус перевозит группу курсантов.","Автобусом управляет водитель-курсант.","Автобус движется в составе транспортной колонны."],"c":3,"e":"<p>Опознавательный знак «Колонна» , установленный на автобусе, означает, что автобус движется в составе транспортной колонны.</p>","image":"assets/adrive-questions/q102603501.webp"},{"id":102603502,"themeId":6,"group":1026035,"chapter":26,"chapters":[26],"q":"Как должен быть установлен опознавательный знак «Колонна» на транспортном средстве, движущемся в составе транспортной колонны?","a":["Только на задней стороне кузова слева.","Только на задней стороне кузова справа.","Спереди и сзади транспортного средства."],"c":2,"e":"<p>Опознавательный знак «Колонна» должен быть установлен спереди и сзади транспортного средства, движущегося в составе транспортной колонны.</p>","image":"assets/adrive-questions/q102603502.webp"},{"id":102603601,"themeId":6,"group":1026036,"chapter":26,"chapters":[26],"q":"Как должен быть установлен на транспортном средстве опознавательный знак «Тихоходное транспортное средство»?","a":["Сзади транспортного средства.","Спереди транспортного средства.","Спереди и сзади транспортного средства."],"c":0,"e":"<p>Опознавательный знак «Тихоходное транспортное средство» должен быть установлен сзади транспортного средства.</p>","image":"assets/adrive-questions/q102603601.webp"},{"id":102603602,"themeId":6,"group":1026036,"chapter":26,"chapters":[26],"q":"Какую скорость не может превысить транспортное средство, обозначенное показанным на рисунке опознавательным знаком?","a":["30 км/ч.","40 км/ч.","50 км/ч."],"c":0,"e":"<p>Транспортное средство, обозначенное показанным на рисунке опознавательным знаком «Тихоходное транспортное средство» , не может двигаться со скоростью более 30 км/ч.</p>","image":"assets/adrive-questions/q102603602.webp"},{"id":102603701,"themeId":6,"group":1026037,"chapter":26,"chapters":[26],"q":"Как может быть установлен на механическом транспортном средстве опознавательный знак «Отличительный знак транспортного средства Республики Беларусь»?","a":["Только на задней стороне кузова слева.","Только на задней стороне кузова справа.","Спереди и сзади транспортного средства."],"c":1,"e":"<p>Опознавательный знак «Отличительный знак транспортного средства Республики Беларусь» может быть установлен на механическом транспортном средстве только на задней стороне кузова справа.</p>","image":"assets/adrive-questions/q102603701.webp"},{"id":102603703,"themeId":6,"group":1026037,"chapter":26,"chapters":[26],"q":"Запрещается ли водителю механического транспортного средства устанавливать показанный на рисунке опознавательный знак, если на транспортном средстве установлены регистрационные знаки, содержащие изображение символа «BY»?","a":["Да, запрещается.","Нет, не запрещается."],"c":1,"e":"<p>Опознавательный знак «Отличительный знак транспортного средства Республики Беларусь» не запрещается устанавливать на механическом транспортном средстве, зарегистрированном в Республике Беларусь, в случае установки на транспортном средстве регистрационных знаков, содержащих изображение символа «BY».</p>","image":"assets/adrive-questions/q102603703.webp"},{"id":102603901,"themeId":6,"group":1026039,"chapter":26,"chapters":[26],"q":"Укажите правильные размеры опознавательного знака «Крупногабаритный груз»:","a":["200 × 200 мм.","300 × 300 мм.","400 × 400 мм.","500 × 500 мм."],"c":2,"e":"<p>Опознавательный знак «Крупногабаритный груз» имеет размеры 400 × 400 мм.</p>","image":"assets/adrive-questions/q102603901.webp"},{"id":102603902,"themeId":6,"group":1026039,"chapter":26,"chapters":[26],"q":"Как правильно должен быть установлен опознавательный знак «Крупногабаритный груз»?","a":["На крайних внешних частях груза, выступающего за габариты транспортного средства.","Спереди и сзади механического транспортного средства, перевозящего крупногабаритный груз.","Только на задней стороне кузова слева механического транспортного средства, перевозящего крупногабаритный груз."],"c":0,"e":"<p>Опознавательный знак «Крупногабаритный груз» должен быть установлен на крайних внешних частях груза, выступающего за габариты транспортного средства.</p>","image":"assets/adrive-questions/q102603902.webp"},{"id":102604001,"themeId":6,"group":1026040,"chapter":26,"chapters":[26],"q":"Что означает опознавательный знак, которым обозначено транспортное средство?","a":["Транспортное средство перевозит опасный груз.","Транспортное средство перевозит скоропортящийся груз.","Транспортное средство перевозит крупногабаритный груз.","Транспортное средство участвует в международном движении."],"c":0,"e":"<p>Показанный опознавательный знак «Опасный груз» , которым обозначено транспортное средство, означает, что оно перевозит опасный груз.</p>","image":"assets/adrive-questions/q102604001.webp"},{"id":102604002,"themeId":6,"group":1026040,"chapter":26,"chapters":[26],"q":"Как называется показанный на рисунке опознавательный знак?","a":["Опасный груз.","Крупногабаритный груз.","Транспортное средство большой длины.","Транспортное средство большой грузоподъёмности."],"c":0,"e":"<p>На рисунке изображён опознавательный знак «Опасный груз» .</p>","image":"assets/adrive-questions/q102604002.webp"},{"id":102604102,"themeId":6,"group":1026041,"chapter":26,"chapters":[26],"q":"Что означает опознавательный знак, которым обозначено транспортное средство?","a":["Транспортное средство перевозит опасный груз.","Транспортным средством управляет водитель — инвалид по слуху.","Транспортным средством управляет инвалид I или II группы, или инвалид III группы с нарушениями опорно-двигательного аппарата, или на транспортном средстве перевозят таких инвалидов."],"c":1,"e":"<p>Показанный опознавательный знак , которым обозначено транспортное средство, означает, что транспортным средством управляет водитель — инвалид по слуху.</p>","image":"assets/adrive-questions/q102604102.webp"},{"id":102604301,"themeId":6,"group":1026043,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак?","a":["Транспортное средство имеет большую длину.","Транспортное средство перевозит опасный груз.","Транспортное средство движется в составе автопоезда.","Транспортное средство имеет большую грузоподъёмность."],"c":0,"e":"<p>Показанный опознавательный знак «Транспортное средство большой длины» означает, что транспортное средство имеет большую длину.</p>","image":"assets/adrive-questions/q102604301.webp"},{"id":102604302,"themeId":6,"group":1026043,"chapter":26,"chapters":[26],"q":"Как называется показанный на рисунке опознавательный знак?","a":["Опасный груз.","Тихоходное транспортное средство.","Транспортное средство большой длины.","Транспортное средство большой грузоподъёмности."],"c":2,"e":"<p>На рисунке изображён опознавательный знак «Транспортное средство большой длины» .</p>","image":"assets/adrive-questions/q102604302.webp"},{"id":102604401,"themeId":6,"group":1026044,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак?","a":["Транспортное средство имеет большую длину.","Транспортное средство перевозит опасный груз.","Транспортное средство движется в составе автопоезда.","Транспортное средство имеет большую грузоподъёмность."],"c":3,"e":"<p>Показанный опознавательный знак «Транспортное средство большой грузоподъёмности» означает, что транспортное средство имеет большую грузоподъёмность.</p>","image":"assets/adrive-questions/q102604401.webp"},{"id":102604402,"themeId":6,"group":1026044,"chapter":26,"chapters":[26],"q":"Как называется показанный на рисунке опознавательный знак?","a":["Опасный груз.","Крупногабаритный груз.","Тихоходное транспортное средство.","Транспортное средство большой длины.","Транспортное средство большой грузоподъёмности."],"c":4,"e":"<p>На рисунке изображён опознавательный знак «Транспортное средство большой грузоподъёмности» .</p>","image":"assets/adrive-questions/q102604402.webp"},{"id":102604501,"themeId":6,"group":1026045,"chapter":26,"chapters":[26],"q":"Как называется показанный на рисунке опознавательный знак?","a":["Инвалид.","Знак опасности.","Инвалид по слуху.","Тихоходное транспортное средство."],"c":0,"e":"<p>На рисунке изображён опознавательный знак «Инвалид» .</p>","image":"assets/adrive-questions/q102604501.webp"},{"id":102604502,"themeId":6,"group":1026045,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак?","a":["Транспортное средство перевозит опасный груз.","Транспортным средством управляет водитель — инвалид по слуху.","Транспортным средством управляет инвалид I или II группы, или инвалид III группы с нарушениями опорно-двигательного аппарата, или на транспортном средстве перевозят таких инвалидов или детей-инвалидов."],"c":2,"e":"<p>На рисунке изображён опознавательный знак «Инвалид» , который означает, что транспортным средством управляет инвалид I или II группы, или инвалид III группы с нарушениями опорно-двигательного аппарата, или на транспортном средстве перевозят таких инвалидов, или детей-инвалидов.</p>","image":"assets/adrive-questions/q102604502.webp"},{"id":102604601,"themeId":6,"group":1026046,"chapter":26,"chapters":[26],"q":"Обязательно ли устанавливать опознавательный знак «Инвалид», если автомобилем управляет инвалид I группы?","a":["Да, обязательно.","Нет, необязательно."],"c":1,"e":"<p>Опознавательный знак «Инвалид» устанавливается по желанию водителя.</p>","image":"assets/adrive-questions/q102604601.webp"},{"id":102604602,"themeId":6,"group":1026046,"chapter":26,"chapters":[26],"q":"Обязательно ли устанавливать опознавательный знак «Инвалид по слуху», если автомобилем управляет водитель — инвалид по слуху III группы?","a":["Да, обязательно.","Нет, необязательно."],"c":0,"e":"<p>Если автомобилем управляет водитель-инвалид по слуху любой группы инвалидности, то опознавательный знак «Инвалид по слуху» устанавливать обязательно.</p>","image":"assets/adrive-questions/q102604602.webp"},{"id":102604701,"themeId":6,"group":1026047,"chapter":26,"chapters":[26],"q":"Что означает показанный на рисунке опознавательный знак?","a":["Транспортное средство перевозит опасный груз.","Транспортным средством управляет водитель-врач.","Транспортным средством управляет водитель — инвалид по слуху.","Транспортным средством управляет инвалид I или II группы, или инвалид III группы с нарушениями опорно-двигательного аппарата, или на транспортном средстве перевозят таких инвалидов."],"c":1,"e":"<p>Показанный опознавательный знак «Врач» , означает, что транспортным средством управляет водитель-врач.</p>","image":"assets/adrive-questions/q102604701.webp"},{"id":102604702,"themeId":6,"group":1026047,"chapter":26,"chapters":[26],"q":"Как называется показанный на рисунке опознавательный знак?","a":["Врач.","Инвалид.","Инвалид по слуху.","Медицинская помощь.","Скорая медицинская помощь."],"c":0,"e":"<p>На рисунке изображён опознавательный знак «Врач» .</p>","image":"assets/adrive-questions/q102604702.webp"},{"id":102604801,"themeId":6,"group":1026048,"chapter":26,"chapters":[26],"q":"Обязательно ли устанавливать опознавательный знак «Врач», если автомобилем управляет врач-терапевт?","a":["Да, обязательно.","Нет, необязательно."],"c":1,"e":"<p>Если автомобилем управляет врач, то опознавательный знак «Врач» устанавливается по желанию водителя.</p>","image":"assets/adrive-questions/q102604801.webp"},{"id":102604802,"themeId":6,"group":1026048,"chapter":26,"chapters":[26],"q":"Как должен быть установлен на автомобиле опознавательный знак «Врач»?","a":["Спереди и сзади автомобиля.","Только на задней стороне кузова слева.","Только на задней стороне кузова справа."],"c":0,"e":"<p>Опознавательный знак «Врач» устанавливается спереди и сзади автомобиля.</p>","image":"assets/adrive-questions/q102604802.webp"},{"id":102604902,"themeId":6,"group":1026049,"chapter":26,"chapters":[26],"q":"Какие из показанных на рисунке опознавательных знаков могут быть установлены на транспортных средствах по желанию водителя?","a":["Только опознавательный знак 1.","Только опознавательный знак 2.","Только опознавательный знак 3.","Опознавательные знаки 1 и 2.","Опознавательные знаки 1 и 3."],"c":4,"e":"<p>Опознавательные знаки под номерами 1 и 3 — «Врач» и «Инвалид» — могут быть установлены на транспортных средствах по желанию водителя.</p> <p>Опознавательный знак «Инвалид по слуху» , показанный под номером 2, должен быть установлен на механических транспортных средствах, управляемых водителями — инвалидами по слуху.</p>","image":"assets/adrive-questions/q102604902.webp"},{"id":102604931,"themeId":6,"group":1026049,"chapter":26,"chapters":[26],"q":"Какие из показанных на рисунке опознавательных знаков должны быть установлены на транспортных средствах при соответствующих условиях?","a":["Только опознавательный знак 1.","Только опознавательный знак 2.","Только опознавательный знак 3.","Опознавательные знаки 1 и 2.","Опознавательные знаки 1 и 3."],"c":1,"e":"<p>Опознавательный знак под номером 2 — «Инвалид по слуху» — должен быть установлен на транспортных средствах при соответствующих условиях.</p> <p>Опознавательные знаки «Шипы» , «Врач» , показанные под номерами 1 и 3, могут быть установлены по желанию водителя.</p>","image":"assets/adrive-questions/q102604931.webp"},{"id":102604951,"themeId":6,"group":1026049,"chapter":26,"chapters":[26],"q":"Какие из показанных на рисунке опознавательных знаков могут быть установлены на транспортных средствах по желанию водителя при соответствующих условиях?","a":["Только знак 3.","Только знаки 3 и 5.","Только знаки 2 и 5.","Только знаки 1, 3 и 5.","Все показанные знаки."],"c":3,"e":"<p>Опознавательные знаки <strong>«Шипы», «Врач» и «Инвалид»</strong> могут устанавливаться <strong>по желанию</strong> водителя согласно Правилам дорожного движения.</p>","image":"assets/adrive-questions/q102604951.webp"},{"id":102605001,"themeId":6,"group":1026050,"chapter":26,"chapters":[26],"q":"Как правильно производится разрешённая Правилами дорожного движения установка световозвращающих лент (полос) на транспортных средствах в соответствии с установленными требованиями?","a":["Красного цвета сзади и спереди.","Красного цвета сзади и белого цвета спереди.","Оранжевого цвета сбоку и красного цвета сзади.","Красного цвета сзади и белого или жёлтого цвета спереди."],"c":1,"e":"<p>Водителю разрешается установка световозвращающих лент красного цвета сзади и белого цвета спереди транспортных средств. Размеры, места установки и другие характеристики световозвращающих лент для каждого типа ТС регламентируются установленными требованиями.</p>","image":null},{"id":102605002,"themeId":6,"group":1026050,"chapter":26,"chapters":[26],"q":"Что из нижеперечисленного разрешается водителю в соответствии с установленными требованиями?","a":["Установка дополнительных фар спереди и сигналов торможения сзади.","Установка световозвращающих лент красного цвета сзади и белого цвета спереди транспортных средств.","Установка дополнительных фонарей освещения регистрационного знака (временного номерного знака)."],"c":1,"e":"<p>Водителю разрешается установка световозвращающих лент красного цвета сзади и белого цвета спереди транспортных средств. Размеры, места установки и другие характеристики световозвращающих лент для каждого типа ТС регламентируются установленными требованиями.</p>","image":null},{"id":102605101,"themeId":6,"group":1026051,"chapter":26,"chapters":[26],"q":"Укажите правильные размеры предупредительного устройства для обозначения гибких связующих звеньев при буксировке механических транспортных средств:","a":["200×200 мм.","300×300 мм.","400×400 мм.","500×500 мм."],"c":0,"e":"<p>Обозначение гибкого связующего звена, предназначенного для буксировки механических ТС, через каждый метр обеспечивает лучшее информирование участников дорожного движения о том, что ТС сцеплены между собой и движутся как одно целое. При этом размеры предупредительных устройств установлены 200×200 мм.</p>","image":"assets/adrive-questions/q102605101.webp"},{"id":102605102,"themeId":6,"group":1026051,"chapter":26,"chapters":[26],"q":"Предупредительные устройства для обозначения гибких связующих звеньев при буксировке механических транспортных средств должны быть выполнены:","a":["В виде щитков размером 200×200 мм.","В виде флажков размером 200×200 мм.","В виде флажков или щитков размером 200×200 мм."],"c":2,"e":"<p>Обозначение гибкого связующего звена, предназначенного для буксировки механических ТС, через каждый метр обеспечивает лучшее информирование участников дорожного движения о том, что ТС сцеплены между собой и движутся как одно целое. При этом размеры предупредительных устройств установлены 200×200 мм.</p>","image":null},{"id":102605201,"themeId":6,"group":1026052,"chapter":26,"chapters":[26],"q":"Какое количество предупредительных устройств должно быть на гибком связующем звене при буксировке?","a":["Не менее трёх.","Не менее двух.","Не менее одного.","От одного до двух."],"c":1,"e":"<p>Правилами дорожного движения установлено, что предупредительных устройств должно быть не менее двух. Однако, обозначение гибкого связующего звена, предназначенного для буксировки механических ТС, через каждый метр обеспечивает лучшее информирование участников дорожного движения о том, что ТС сцеплены между собой и движутся как одно целое.</p>","image":"assets/adrive-questions/q102605201.webp"},{"id":102605203,"themeId":6,"group":1026052,"chapter":26,"chapters":[26],"q":"Правильно ли обозначено гибкое связующее звено при буксировке в показанной ситуации?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>На гибком связующем звене должно быть установлено не менее двух предупредительных устройств. Поэтому в показанной ситуации гибкое связующее звено обозначено неправильно.</p>","image":"assets/adrive-questions/q102605203.webp"},{"id":102605301,"themeId":6,"group":1026053,"chapter":26,"chapters":[26],"q":"Для легковых автомобилей участвовать в дорожном движении с 1 декабря по 1 марта:","a":["Рекомендуется при условии оборудования ошипованными шинами.","Разрешается при условии оборудования шинами, укомплектованными цепями противоскольжения.","Разрешается при условии оборудования шинами, предназначенными для эксплуатации в зимних условиях.","Рекомендуется при условии оборудования шинами, предназначенными для эксплуатации в зимних условиях."],"c":2,"e":"<p>При участии в дорожном движении с 1 декабря по 1 марта легковые автомобили должны быть оборудованы зимними шинами. Зимние шины устанавливаются на всех колёсах транспортного средства.</p>","image":"assets/adrive-questions/q102605301.webp"},{"id":102605302,"themeId":6,"group":1026053,"chapter":26,"chapters":[26],"q":"Участвовать в дорожном движении с 1 декабря по 1 марта разрешено на транспортных средствах:","a":["Оборудованных ошипованными шинами.","Оборудованных шинами, укомплектованными цепями противоскольжения.","Оборудованных зимними шинами."],"c":2,"e":"<p>Участвовать в дорожном движении с 1 декабря по 1 марта разрешается только на транспортных средствах, оборудованных шинами, предназначенными для эксплуатации в зимних условиях.</p>","image":"assets/adrive-questions/q102605302.webp"},{"id":400100101,"themeId":6,"group":4001001,"chapter":31,"chapters":[31],"q":"При каком из перечисленных условий запрещается участие транспортного средства в дорожном движении?","a":["Уровень тормозной жидкости в бачке находится ниже максимальной отметки.","Нарушена герметичность гидравлического тормозного привода, имеется подтекание тормозной жидкости.","В гидравлическом приводе рабочей тормозной системы находится тормозная жидкость, не предусмотренная изготовителем для данного транспортного средства."],"c":1,"e":"<p>К гидравлическому тормозному приводу транспортного средства предъявляется следующее требование: не допускается подтекание тормозной жидкости из главного тормозного цилиндра, из рабочих тормозных цилиндров, а также в местах соединения трубопроводов и шлангов.</p>","image":"assets/adrive-questions/q400100101.webp"},{"id":400100102,"themeId":6,"group":4001001,"chapter":31,"chapters":[31],"q":"При каких неисправностях запрещается участие транспортного средства в дорожном движении?","a":["Имеются детали тормозной системы с трещинами или остаточной деформацией.","Нарушена герметичность гидравлического тормозного привода, имеется подтекание тормозной жидкости.","Имеется не предусмотренный конструкцией контакт трубопровода тормозного привода с элементами транспортного средства.","При любой неисправности из перечисленных запрещается участие в дорожном движении."],"c":3,"e":"<p>Запрещается участие транспортного средства в дорожном движении при нарушении герметичности гидравлического тормозного привода, при имеющемся подтекании тормозной жидкости, если имеются детали тормозной системы с трещинами или остаточной деформацией, имеется не предусмотренный конструкцией контакт трубопровода тормозного привода с элементами транспортного средства.</p> <p>Данные неисправности могут привести к полной потере тормозных свойств транспортного средства.</p>","image":null},{"id":400100302,"themeId":6,"group":4001003,"chapter":31,"chapters":[31],"q":"В каком из перечисленных ответов правильно указана максимальная величина уклона, на котором стояночная тормозная система должна обеспечивать неподвижное состояние легкового автомобиля в снаряжённом состоянии?","a":["16 процентов.","21 процент.","23 процента.","31 процент.","32 процента."],"c":2,"e":"<p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии.<br> В соответствии с Правилами дорожного движения максимальная величина уклона, при которой стояночная тормозная система должна обеспечивать неподвижное состояние легковых автомобилей в снаряжённом состоянии, составляет до 23 процентов включительно.</p>","image":"assets/adrive-questions/q400100302.webp"},{"id":400100303,"themeId":6,"group":4001003,"chapter":31,"chapters":[31],"q":"В каком из перечисленных ответов правильно указана максимальная величина уклона, на котором стояночная тормозная система должна обеспечивать неподвижное состояние легкового автомобиля с полной нагрузкой?","a":["16 процентов.","21 процент.","23 процента.","31 процент.","32 процента."],"c":0,"e":"<p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии.<br> В соответствии с Правилами дорожного движения максимальная величина уклона, при которой стояночная тормозная система должна обеспечивать неподвижное состояние всех автомобилей (в том числе легковых) с полной нагрузкой, составляет до 16 процентов включительно.</p>","image":null},{"id":400100401,"themeId":6,"group":4001004,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, у которого рычаг управления стояночной тормозной системой не удерживается запирающим устройством?","a":["Запрещается.","Разрешается на равнинной местности.","Разрешается для полноприводных автомобилей.","Разрешается для автомобилей с механической коробкой передач.","Разрешается для автомобилей с автоматической коробкой передач."],"c":0,"e":"<p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии. При этом, если рычаг управления стояночной тормозной системы не удерживается запирающим устройством, обеспечить длительное удержание транспортного средства в неподвижном состоянии, используя только стояночную тормозную систему, невозможно.</p>","image":null},{"id":400100402,"themeId":6,"group":4001004,"chapter":31,"chapters":[31],"q":"При каком условии из перечисленных запрещается участие в дорожном движении легкового автомобиля?","a":["Затруднено выключение из работы стояночной тормозной системы.","Рычаг управления стояночной тормозной системой затягивается с большим усилием.","Рычаг управления стояночной тормозной системой не удерживается запирающим устройством.","Участие в дорожном движении запрещено во всех перечисленных случаях."],"c":2,"e":"<p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии. При этом, если рычаг управления стояночной тормозной системы не удерживается запирающим устройством, обеспечить длительное удержание транспортного средства в неподвижном состоянии, используя только стояночную тормозную систему, невозможно.</p>","image":"assets/adrive-questions/q400100402.webp"},{"id":400100501,"themeId":6,"group":4001005,"chapter":31,"chapters":[31],"q":"Какую минимальную величину не должен превышать люфт в рулевом управлении легкового автомобиля?","a":["10 градусов.","12 градусов.","16 градусов.","20 градусов.","23 градуса."],"c":0,"e":"<p>В соответствии с Правилами дорожного движения суммарный люфт в рулевом управлении не должен превышать 10 градусов для легковых автомобилей. Наличие суммарного люфта, превышающего допустимые значения, указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления. Данные неисправности могут стать причиной возникновения угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400100501.webp"},{"id":400100502,"themeId":6,"group":4001005,"chapter":31,"chapters":[31],"q":"Легковой автомобиль не должен участвовать в дорожном движении, если суммарный люфт в рулевом управлении составляет:","a":["5 градусов.","10 градусов.","15 градусов.","Величину, указанную во втором или третьем ответе."],"c":2,"e":"<p>В соответствии с Правилами дорожного движения суммарный люфт в рулевом управлении не должен превышать 10 градусов для легковых автомобилей. Наличие суммарного люфта, превышающего допустимые значения, указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления. Данные неисправности могут стать причиной возникновения угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400100502.webp"},{"id":400100601,"themeId":6,"group":4001006,"chapter":31,"chapters":[31],"q":"Какую минимальную величину не должен превышать люфт в рулевом управлении грузового автомобиля, созданного на базе легкового автомобиля?","a":["10 градусов.","12 градусов.","16 градусов.","20 градусов.","25 градусов."],"c":0,"e":"<p>В соответствии с Правилами дорожного движения суммарный люфт в рулевом управлении не должен превышать 10 градусов для грузовых автомобилей, созданных на базе легковых автомобилей. Наличие суммарного люфта, превышающего допустимые значения, указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления. Данные неисправности могут стать причиной возникновения угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400100601.webp"},{"id":400100602,"themeId":6,"group":4001006,"chapter":31,"chapters":[31],"q":"Грузовой автомобиль, созданный на базе легкового автомобиля, не должен участвовать в дорожном движении, если суммарный люфт в рулевом управлении составляет:","a":["5 градусов.","25 градусов.","30 градусов.","Величину, указанную во втором или третьем ответе."],"c":3,"e":"<p>В соответствии с Правилами дорожного движения суммарный люфт в рулевом управлении не должен превышать 10 градусов для грузовых автомобилей, созданных на базе легковых автомобилей. Наличие суммарного люфта, превышающего допустимые значения, указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления. Данные неисправности могут стать причиной возникновения угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400100602.webp"},{"id":400100701,"themeId":6,"group":4001007,"chapter":31,"chapters":[31],"q":"Какую минимальную величину не должен превышать люфт в рулевом управлении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, созданного не на базе легкового автомобиля?","a":["10 градусов.","12 градусов.","16 градусов.","20 градусов.","25 градусов."],"c":4,"e":"<p>В соответствии с Правилами дорожного движения суммарный люфт в рулевом управлении не должен превышать 25 градусов для грузовых автомобилей, созданных не на базе легковых автомобилей. Наличие суммарного люфта, превышающего допустимые значения, указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления. Данные неисправности могут стать причиной возникновения угрозы безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400100701.webp"},{"id":400100801,"themeId":6,"group":4001008,"chapter":31,"chapters":[31],"q":"При каком из перечисленных условий запрещается участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, созданного не на базе легкового автомобиля?","a":["Суммарный люфт в рулевом управлении составляет 20 градусов.","В снаряжённом состоянии автомобиль не удерживается стояночной тормозной системой на уклоне 20%.","Запрещается участие в дорожном движении при любом условии из перечисленных."],"c":1,"e":"<p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии. В соответствии с Правилами дорожного движения максимальная величина уклона, при которой стояночная тормозная система должна обеспечивать неподвижное состояние грузовых автомобилей в снаряжённом состоянии составляет до 31 процента включительно.</p>","image":"assets/adrive-questions/q400100801.webp"},{"id":400100802,"themeId":6,"group":4001008,"chapter":31,"chapters":[31],"q":"При каком из перечисленных условий запрещается участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, созданного на базе легкового автомобиля?","a":["Суммарный люфт в рулевом управлении составляет 20 градусов.","В снаряжённом состоянии автомобиль не удерживается стояночной тормозной системой на уклоне 20%.","Запрещается участие в дорожном движении при любом условии из перечисленных."],"c":2,"e":"<p>Наличие суммарного люфта, превышающего допустимые значения (для легкового автомобиля и автомобилей, созданных на базе легковых — не более 10 градусов), указывает на чрезмерный износ деталей рулевого управления, на нарушение регулировки либо ослабление крепления узлов рулевого управления.</p> <p>Основное назначение стояночной тормозной системы — это удержание транспортного средства на уклоне дороги в неподвижном состоянии. В соответствии с Правилами дорожного движения максимальная величина уклона, при которой стояночная тормозная система должна обеспечивать неподвижное состояние грузовых автомобилей в снаряжённом состоянии, составляет до 31 процента включительно.</p>","image":"assets/adrive-questions/q400100802.webp"},{"id":400100901,"themeId":6,"group":4001009,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении при отсутствии жидкости в бачке гидроусилителя рулевого управления?","a":["Запрещается.","Разрешается при движении по дорогам при наличии снежного покрова.","Разрешается при движении по дорогам с усовершенствованным покрытием."],"c":0,"e":"<p>Запрещается участие в дорожном движении при отсутствии жидкости в бачке гидроусилителя рулевого управления, так как без рабочей жидкости гидроусилитель не действует. Также при движении без жидкости в приводе гидроусилителя возможен выход из строя насоса гидроусилителя и деталей рулевого механизма.</p>","image":null},{"id":400100902,"themeId":6,"group":4001009,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении, если неисправен насос гидроусилителя рулевого управления?","a":["Запрещается.","Разрешается только для легковых автомобилей.","Разрешается при движении на небольшие расстояния."],"c":0,"e":"<p>Запрещается участие в дорожном движении, если неисправен насос гидроусилителя рулевого управления, который может привести рулевую рейку в полностью неисправное состояние и как следствие к неисправности рулевой системы, при котором её дальнейшая эксплуатация будет угрожать безопасности дорожного движения.</p>","image":null},{"id":400101001,"themeId":6,"group":4001010,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, у которого вследствие наезда на препятствие деформирована рулевая тяга?","a":["Запрещается.","Разрешается, если это не затрудняет управления автомобилем.","Разрешается, если автомобили этой марки сняты с производства."],"c":0,"e":"<p>Правила дорожного движения запрещают участвовать в дорожном движении на транспортном средстве, у которого детали рулевого управления (в том числе рулевая рейка) имеют следы остаточной деформации.</p>","image":null},{"id":400101002,"themeId":6,"group":4001010,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если при управлении им вращение рулевого колеса происходит с рывками и заеданиями?","a":["Запрещается.","Разрешается, если заедания происходят только при движении на невысоких скоростях или на стоянке.","Разрешается, если автомобиль не оборудован гидроусилителем (электроусилителем) рулевого управления."],"c":0,"e":"<p>Участие в дорожном движении легкового автомобиля при появлении рывков и (или) заеданий при вращении рулевого колеса свидетельствует о неисправности рулевого управления. Поэтому эксплуатация такого механического ТС должна быть прекращена до устранения неисправности.</p>","image":"assets/adrive-questions/q400101002.webp"},{"id":400101101,"themeId":6,"group":4001011,"chapter":31,"chapters":[31],"q":"Разрешается ли установка на легковой автомобиль фар от автомобиля другой марки (модели)?","a":["Нет, не разрешается.","Разрешается, если автомобиль снят с производства.","Разрешается, если фары имеют те же характеристики."],"c":1,"e":"<p>Использование внешних световых приборов от ТС других марок и моделей допускается лишь в том случае, если данное транспортное средство снято с производства, при соблюдении технических норм, определяющих исправность и безопасность работы внешних световых приборов.</p>","image":"assets/adrive-questions/q400101101.webp"},{"id":400101102,"themeId":6,"group":4001011,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля с блоком задних фонарей от другой марки (модели) автомобиля?","a":["Нет, не разрешается.","Разрешается, если автомобиль снят с производства.","Разрешается, если фонари имеют ту же конфигурацию (расположение)."],"c":1,"e":"<p>Использование внешних световых приборов от ТС других марок и моделей допускается лишь в том случае, если данное транспортное средство снято с производства, при соблюдении технических норм, определяющих исправность и безопасность работы внешних световых приборов.</p>","image":"assets/adrive-questions/q400101102.webp"},{"id":400101201,"themeId":6,"group":4001012,"chapter":31,"chapters":[31],"q":"При какой неисправности из перечисленных разрешается участие в дорожном движении транспортного средства?","a":["Загрязнены фары автомобиля.","Дополнительный сигнал торможения работает в проблесковом режиме.","Не работает в установленном режиме световой указатель правого поворота.","При любой неисправности из перечисленных участие в дорожном движении запрещается."],"c":3,"e":"<p>Участие в дорожном движении запрещается, если загрязнены фары автомобиля, сигналы торможения работают в проблесковом режиме, не работает в установленном режиме световой указатель правого поворота.</p>","image":null},{"id":400101202,"themeId":6,"group":4001012,"chapter":31,"chapters":[31],"q":"При какой неисправности из перечисленных разрешается участие в дорожном движении транспортного средства?","a":["На блоке задних фонарей имеется трещина.","Загрязнены световозвращатели автомобиля.","Сигналы торможения работают в проблесковом режиме.","При любой неисправности из перечисленных участие в дорожном движении запрещается."],"c":0,"e":"<p>Правилами дорожного движения запрещается участие в дорожном движении, если загрязнены световозвращатели или внешние световые приборы автомобиля, также запрещается участие в дорожном движении, если сигналы торможения работают в проблесковом режиме.<br> При этом участие в дорожном движении не запрещается, если на блоке задних фонарей имеется трещина.</p>","image":null},{"id":400101301,"themeId":6,"group":4001013,"chapter":31,"chapters":[31],"q":"Разрешается ли установка дополнительных фар на автомобиль?","a":["Разрешается установка двух противотуманных фар.","Разрешается установка двух фар вместо противотуманных.","Разрешается установка двух фар на крышу легкового автомобиля повышенной проходимости.","Разрешается установка двух фар на грузовой автомобиль, участвующий в международном движении."],"c":0,"e":"<p>На автомобиль, согласно Правилам дорожного движения, разрешается дополнительно установка только двух противотуманных фар.</p>","image":null},{"id":400101302,"themeId":6,"group":4001013,"chapter":31,"chapters":[31],"q":"Разрешается ли установка двух противотуманных фар, если они не предусмотрены конструкцией автомобиля?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>На автомобиль, согласно Правилам дорожного движения, разрешается дополнительно установка только двух противотуманных фар.</p>","image":"assets/adrive-questions/q400101302.webp"},{"id":400101401,"themeId":6,"group":4001014,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении автомобиля, у которого из двух работает в установленном режиме только один стеклоочиститель ветрового стекла?","a":["Нет, не разрешается.","Запрещается только во время выпадения осадков.","Запрещается в том случае, если неработающий стеклоочиститель расположен со стороны водителя."],"c":0,"e":"<p>При наличии неисправности стеклоочистителей ветрового стекла Правилами дорожного движения запрещается участие в дорожном движении. В случае, если отсутствуют атмосферные осадки, при невозможности устранить неисправность, водителю разрешено двигаться только к месту ремонта или стоянки.</p>","image":null},{"id":400101402,"themeId":6,"group":4001014,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении автомобиля, у которого стеклоочиститель заднего стекла работает с частотой перемещения щётки в режиме максимальной скорости менее 35 двойных ходов в минуту?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Требование Правил дорожного движения (частота перемещения щёток по мокрому стеклу в режиме максимальной скорости стеклоочистителей по ветровому стеклу менее 35 двойных ходов в минуту) направлено на обеспечение безопасности дорожного движения во время интенсивного выпадения атмосферных осадков и установлено только для стеклоочистителей ветрового стекла автомобиля. Для остальных стёкол максимальная частота перемещения щёток не установлена.</p>","image":"assets/adrive-questions/q400101402.webp"},{"id":400101501,"themeId":6,"group":4001015,"chapter":31,"chapters":[31],"q":"Какая минимальная частота перемещения щёток по мокрому стеклу в режиме максимальной скорости стеклоочистителей ветрового стекла допускается Правилами дорожного движения?","a":["20 двойных ходов в минуту.","25 двойных ходов в минуту.","30 двойных ходов в минуту.","35 двойных ходов в минуту.","40 двойных ходов в минуту."],"c":3,"e":"<p>Требование Правил дорожного движения (частота перемещения щёток по мокрому стеклу в режиме максимальной скорости стеклоочистителей по ветровому стеклу менее 35 двойных ходов в минуту) направлено на обеспечение безопасности дорожного движения во время интенсивного выпадения атмосферных осадков.</p>","image":"assets/adrive-questions/q400101501.webp"},{"id":400101502,"themeId":6,"group":4001015,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, щётки стеклоочистителей ветрового стекла которого по мокрому стеклу в режиме максимальной скорости совершают 37 двойных ходов в минуту?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Наличие и исправность стеклоочистителей является важным условием обеспечения обзорности дороги в условиях выпадения атмосферных осадков. Частота перемещения щёток по мокрому стеклу в режиме максимальной скорости стеклоочистителей должна быть не менее 35 двойных ходов в минуту.</p>","image":"assets/adrive-questions/q400101502.webp"},{"id":400101503,"themeId":6,"group":4001015,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, щётки стеклоочистителей ветрового стекла которого по мокрому стеклу в режиме максимальной скорости совершают 32 двойных хода в минуту?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Наличие и исправность стеклоочистителей является важным условием обеспечения обзорности дороги в условиях выпадения атмосферных осадков. Частота перемещения щёток по мокрому стеклу в режиме максимальной скорости стеклоочистителей должна быть не менее 35 двойных ходов в минуту.</p>","image":"assets/adrive-questions/q400101503.webp"},{"id":400101601,"themeId":6,"group":4001016,"chapter":31,"chapters":[31],"q":"Разрешается ли участвовать в дорожном движении легковому автомобилю, у которого неисправны стеклоомыватели?","a":["Запрещается.","Разрешается только в зимнее время при замерзании жидкости стеклоомывателей.","Разрешается только при работающих в установленном режиме стеклоочистителях."],"c":0,"e":"<p>Стеклоомыватели должны обеспечивать подачу жидкости в зону очистки стекла в количестве, достаточном для смачивания стекла. Функционирование стеклоомывателя должно обеспечить работу стеклоочистителя ветрового (лобового) стекла в установленном режиме, а также на некоторых автомобилях — стеклоочистителя заднего стекла и стёкол фар.</p>","image":"assets/adrive-questions/q400101601.webp"},{"id":400101602,"themeId":6,"group":4001016,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев водитель при невозможности устранить неисправность не может продолжить движение к месту стоянки или ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения?","a":["Не работают стеклоочистители в ясную погоду.","Не работают стеклоомыватели во время выпадения осадков.","Не работают в установленном режиме световые указатели поворотов в тёмное время суток.","Во всех перечисленных случаях разрешено продолжить движение к месту стоянки или ремонта."],"c":3,"e":"<p>Во всех перечисленных случаях при невозможности устранить перечисленные неисправности водитель может продолжить движение к месту стоянки или ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения.</p>","image":null},{"id":400101701,"themeId":6,"group":4001017,"chapter":31,"chapters":[31],"q":"При движении по дороге из-под колёс встречного автомобиля в ветровое стекло попал камень, образовавшаяся трещина попала в зону, очищаемую стеклоочистителем со стороны водителя. Как должен поступить водитель в такой ситуации?","a":["Прекратить дальнейшее движение.","Продолжать движение, однако при ближайшей возможности заменить ветровое стекло.","Следовать к месту стоянки или ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения."],"c":2,"e":"<p>Наличие трещин на стекле ухудшает обзорность с места водителя. При выпадении атмосферных осадков очистка стекла стеклоочистителем в зоне трещин выполняется некачественно, также наличие трещины (трещин) в зоне активного внимания водителя ведёт к повышенной зрительной усталости.</p>","image":"assets/adrive-questions/q400101701.webp"},{"id":400101702,"themeId":6,"group":4001017,"chapter":31,"chapters":[31],"q":"В каком случае из перечисленных при наличии трещины (трещин) на ветровом стекле автомобиля разрешается участвовать в дорожном движении?","a":["Если трещина (трещины) находятся вне зоны, очищаемой стеклоочистителями.","Если трещина (трещины) находятся вне зоны, очищаемой стеклоочистителем со стороны водителя.","Если трещина (трещины) находятся только в зоне, очищаемой стеклоочистителем с пассажирской стороны.","Разрешается участвовать в дорожном движении во всех перечисленных случаях."],"c":3,"e":"<p>Наличие трещины (трещин) в зоне активного внимания водителя ведёт к повышенной зрительной усталости. Если же трещина находится вне зоны активного внимания водителя (вне зоны, очищаемой стеклоочистителем со стороны водителя), участвовать в дорожном движении не запрещается.</p>","image":null},{"id":400101803,"themeId":6,"group":4001018,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если остаточная высота рисунка протектора шин передних колёс составляет 1.9 мм, а задних — 1.7 мм (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только по дорогам с неинтенсивным движением."],"c":0,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора шин легковых автомобилей для участия в дорожном движении, и она составляет 1.6 мм (кроме зимних шин) как для передних, так и для задних шин автомобиля (для квадрициклов — 0.8 мм).</p>","image":"assets/adrive-questions/q400101803.webp"},{"id":400101831,"themeId":6,"group":4001018,"chapter":31,"chapters":[31],"q":"Какая минимальная остаточная высота рисунка протектора шин легковых автомобилей (за исключением квадрициклов) допускается Правилами дорожного движения для участия в дорожном движении (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["0.8 мм.","1 мм.","1.6 мм.","1.8 мм.","2 мм."],"c":2,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора шин легковых автомобилей для участия в дорожном движении, и она составляет 1.6 мм (кроме зимних шин), для квадрициклов — 0.8 мм.</p>","image":"assets/adrive-questions/q400101831.webp"},{"id":400101832,"themeId":6,"group":4001018,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля (за исключением квадрицикла), если остаточная высота рисунка протектора шин передних колёс составляет 2 мм, а задних — 1.4 мм (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается только по дорогам с неинтенсивным движением."],"c":1,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора шин легковых автомобилей для участия в дорожном движении, и она составляет 1.6 мм (кроме зимних шин), для квадрициклов — 0.8 мм.</p>","image":"assets/adrive-questions/q400101832.webp"},{"id":400101851,"themeId":6,"group":4001018,"chapter":31,"chapters":[31],"q":"При какой минимальной остаточной высоте рисунка протектора зимних шин, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии, допускается участие в дорожном движении легкового автомобиля во время эксплуатации на указанном покрытии?","a":["1.0 мм.","2.0 мм.","4.0 мм.","5.0 мм."],"c":2,"e":"<p><strong>Зимние шины</strong> механических транспортных средств, предназначенные для эксплуатации на обледеневшем или заснеженном дорожном покрытии, во время эксплуатации на указанном покрытии должны иметь остаточную высоту рисунка протектора <strong>не менее 4 мм</strong>.</p>","image":"assets/adrive-questions/q400101851.webp"},{"id":400101931,"themeId":6,"group":4001019,"chapter":31,"chapters":[31],"q":"Какая допускается Правилами дорожного движения минимальная остаточная высота рисунка протектора шин грузового автомобиля с технически допустимой общей массой до 3.5 тонны для участия в дорожном движении (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["0.8 мм.","1 мм.","1.6 мм.","1.8 мм.","2 мм."],"c":2,"e":"<p>Минимальная разрешённая остаточная высота рисунка протектора шин грузовых автомобилей, имеющих технически допустимую общую массу не более 3.5 тонны, для участия в дорожном движении составляет 1.6 мм (кроме зимних шин).</p>","image":"assets/adrive-questions/q400101931.webp"},{"id":400101933,"themeId":6,"group":4001019,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, если остаточная высота рисунка протектора шин передних колёс составляет 2.2 мм, а задних — 1.7 мм (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["Нет, не разрешается.","Да, разрешается.","Разрешается только по дорогам с неинтенсивным движением."],"c":1,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора шин грузовых автомобилей с технически допустимой общей массой до 3.5 тонны для участия в дорожном движении, и она составляет 1.6 мм (кроме зимних шин) как для передних, так и для задних шин автомобиля.</p>","image":"assets/adrive-questions/q400101933.webp"},{"id":400102001,"themeId":6,"group":4001020,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если минимальная остаточная высота рисунка протектора шин составляет 1.7 мм, но появился один индикатор износа, расположенный по дну канавки протектора, при равномерном износе беговой дорожки?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, если использовать автомобиль только для перевозки грузов."],"c":1,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора легкового автомобиля, которая составляет 1.6 мм (кроме зимних шин). Для удобства определения фактического износа шины изготовитель оснащает шину индикаторами износа, расположенными по дну канавок протектора. Индикатор износа выглядит как ребристый выступ внутри протектора.</p> <p>Изготовитель автомобильных шин, исходя из расчётных условий эксплуатации шины (проходимость, скоростные показатели и прочее), может <strong>устанавливать индикаторы износа на большую остаточную высоту протектора</strong> (более 1.6 мм). Если шина изнашивается до такого индикатора при равномерном износе, эксплуатировать такую шину запрещается.</p>","image":"assets/adrive-questions/q400102001.webp"},{"id":400102002,"themeId":6,"group":4001020,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если минимальная остаточная высота рисунка протектора шин составляет 1.8 мм, но появились два индикатора износа, расположенные по дну канавки протектора, в каждом из двух сечений при неравномерном износе беговой дорожки?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, если использовать автомобиль только для перевозки грузов."],"c":1,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора легкового автомобиля, которая составляет 1.6 мм (кроме зимних шин). Индикатор износа выглядит как ребристый выступ внутри протектора. Если шина изнашивается до появления двух таких индикаторов при неравномерном износе, эксплуатировать такую шину запрещается.</p>","image":"assets/adrive-questions/q400102002.webp"},{"id":400102003,"themeId":6,"group":4001020,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля, если минимальная остаточная высота рисунка протектора шин составляет 1.8 мм, но появился один индикатор износа, расположенный по дну канавки протектора, при неравномерном износе беговой дорожки (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии)?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается, если использовать автомобиль только для перевозки грузов."],"c":0,"e":"<p>Правилами дорожного движения регламентируется минимальная остаточная высота рисунка протектора легкового автомобиля, которая составляет 1.6 мм (кроме зимних шин). Индикатор износа выглядит как ребристый выступ внутри протектора. Если шина изнашивается до появления одного такого индикатора при неравномерном износе, эксплуатировать такую шину пока ещё не запрещается.</p>","image":"assets/adrive-questions/q400102003.webp"},{"id":400102101,"themeId":6,"group":4001021,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, если минимальная остаточная высота рисунка протектора шин (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии) составляет 1.7 мм, но появился один индикатор износа, расположенный по дну канавки протектора, при равномерном износе беговой дорожки?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается при движении по дорогам без усовершенствованного покрытия."],"c":1,"e":"<p>Шина считается непригодной к эксплуатации, если появился один индикатор износа, расположенный по дну канавки протектора, при равномерном износе.</p>","image":"assets/adrive-questions/q400102101.webp"},{"id":400102102,"themeId":6,"group":4001021,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, если минимальная остаточная высота рисунка протектора шин (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии) составляет 1.8 мм, но появились два индикатора износа, расположенные по дну канавки протектора, в каждом из двух сечений при неравномерном износе беговой дорожки?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается при движении по дорогам без усовершенствованного покрытия."],"c":1,"e":"<p>Шина считается непригодной к эксплуатации, если появилось два индикатора в каждом из двух сечений — при неравномерном износе беговой дорожки.</p>","image":"assets/adrive-questions/q400102102.webp"},{"id":400102103,"themeId":6,"group":4001021,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении грузового автомобиля с технически допустимой общей массой до 3.5 тонны, если минимальная остаточная высота рисунка протектора шин (кроме зимних шин механических транспортных средств, предназначенных для эксплуатации на обледеневшем или заснеженном дорожном покрытии во время эксплуатации на указанном покрытии) составляет 1.8 мм, но появился один индикатор износа, расположенный по дну канавки протектора, при неравномерном износе беговой дорожки?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается при движении по дорогам без усовершенствованного покрытия."],"c":0,"e":"<p>Шина считается пригодной к эксплуатации, если появился только один индикатор износа, расположенный по дну канавки протектора, при неравномерном износе беговой дорожки.</p>","image":"assets/adrive-questions/q400102103.webp"},{"id":400102201,"themeId":6,"group":4001022,"chapter":31,"chapters":[31],"q":"В каком случае разрешается участвовать в дорожном движении легковому автомобилю с прицепом при отсутствии одной из гаек крепления колеса?","a":["Если отсутствует гайка крепления колеса прицепа.","Если отсутствует гайка крепления заднего колеса автомобиля или прицепа.","Не разрешается в любом случае."],"c":2,"e":"<p>Легковому автомобилю при отсутствии гайки крепления колеса запрещается участие в дорожном движении, это может привести к срыву колеса во время движения и, как следствие, к ДТП. Также запрещается участие в дорожном движении при отсутствии гайки крепления колеса прицепа.</p>","image":null},{"id":400102202,"themeId":6,"group":4001022,"chapter":31,"chapters":[31],"q":"Как Вы должны поступить, если при осмотре автомобиля в пути обнаружите отсутствие одного болта крепления колеса?","a":["Прекратите дальнейшее движение.","Проверите крепление остальных болтов и будете продолжать движение, периодически останавливаясь для проверки надёжности их крепления.","Проверите крепление остальных болтов и будете следовать к ближайшему месту ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения."],"c":2,"e":"<p>Если при осмотре автомобиля в пути обнаружено отсутствие болта (гайки) крепления колеса, водителю необходимо проверить крепление остальных гаек и следовать к ближайшему месту ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400102202.webp"},{"id":400102301,"themeId":6,"group":4001023,"chapter":31,"chapters":[31],"q":"Допускается ли в каком-либо из перечисленных случаев участие в дорожном движении?","a":["На одну ось прицепа к легковому автомобилю установлены диагональные шины совместно с радиальными.","На одну ось легкового автомобиля установлены диагональные шины совместно с радиальными.","На заднюю ось грузового автомобиля с технически допустимой общей массой до 3.5 тонны установлены диагональные шины совместно с радиальными.","Во всех перечисленных случаях участие в дорожном движении запрещается."],"c":3,"e":"<p>Согласно Правилам дорожного движения запрещается участие в дорожном движении, когда на одну ось легкового автомобиля или прицепа к нему установлены радиальные шины совместно с диагональными. Это может привести к заносу или опрокидыванию автомобиля на скользком, заснеженном или обледенелом покрытии, а также при экстренном торможении.</p>","image":null},{"id":400102401,"themeId":6,"group":4001024,"chapter":31,"chapters":[31],"q":"При каком из перечисленных условий легковому автомобилю запрещается участие в дорожном движении?","a":["На колёсах задней оси имеется растрескивание от старения резины.","На декоративных колпаках передних колёс имеются трещины и сколы.","На передней оси в летнее время установлены шины с летним рисунком протектора, на задней оси — с всесезонным.","Участие в дорожном движении запрещается при любом из перечисленных условий."],"c":0,"e":"<p>Механические повреждения шин в виде пробоев, порезов, разрывов, расслоения каркаса, отслоение протектора или боковины, трещины от старения резины могут вызвать быструю потерю давления в шине, а в некоторых случаях разрыв шины во время движения, что может привести к потере управления.</p>","image":null},{"id":400102402,"themeId":6,"group":4001024,"chapter":31,"chapters":[31],"q":"При каком из перечисленных условий грузовому автомобилю с технически допустимой общей массой до 3.5 тонны не запрещается участие в дорожном движении?","a":["На задней оси установлены шины с различным типом рисунка протектора.","На заднем двускатном колесе применены радиальная и диагональная шины.","На передней оси установлены радиальные шины, на задней оси — диагональные.","Участие в дорожном движении запрещается при любом из перечисленных условий."],"c":2,"e":"<p>Из перечисленных условий Правилами дорожного движения не запрещается участие в дорожном движении, когда на грузовом автомобиле с технически допустимой общей массой до 3.5 тонны на передней оси установлены радиальные шины, на задней оси — диагональные. Автомобильные шины различных конструкций по-разному будут реагировать при торможении и изменении направления движения транспортного средства, поэтому применение их на одной оси автомобиля запрещено.</p>","image":null},{"id":400102441,"themeId":6,"group":4001024,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев запрещается участие в дорожном движении автомобиля с ошипованными шинами?","a":["Ошипованные шины установлены только на переднюю ось автомобиля.","Ошипованные шины установлены в летний период.","В обоих перечисленных случаях участие в дорожном движении автомобиля запрещается."],"c":2,"e":"<p>Запрещается участие в дорожном движении, если ошипованные шины установлены не на все оси транспортного средства, а также если они установлены в летний период (июнь, июль, август).</p>","image":null},{"id":400102501,"themeId":6,"group":4001025,"chapter":31,"chapters":[31],"q":"Разрешается ли участвовать в дорожном движении на легковом автомобиле, у которого шина заднего левого колеса имеет несколько порезов?","a":["Нет, не разрешается.","Разрешается только в случае, если порезы не обнажают корд."],"c":1,"e":"<p>Механические повреждения шин в виде пробоев, порезов, разрывов, расслоения каркаса, отслоение протектора или боковины, трещины от старения резины могут вызвать быструю потерю давления в шине, а в некоторых случаях разрыв шины во время движения, что может привести к потере управления. Однако, если порезы недостаточно глубокие, не обнажают корд автомобильной шины, эксплуатировать такую шину не запрещается.</p>","image":"assets/adrive-questions/q400102501.webp"},{"id":400102601,"themeId":6,"group":4001026,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля с дизельным двигателем, если дымность отработавших газов превышает установленную величину?","a":["Нет, не разрешается.","Разрешается на автомобилях, изготовленных более чем 10 лет назад.","Разрешается, так как это может быть обусловлено использованием некачественного топлива."],"c":0,"e":"<p>Участие в дорожном движении легкового автомобиля с повышенной токсичностью (бензиновые двигатели) или дымностью (дизельные двигатели) отработавших газов приводит к загрязнению окружающей среды и возникновению угрозы отравления участников дорожного движения.</p>","image":"assets/adrive-questions/q400102601.webp"},{"id":400102602,"themeId":6,"group":4001026,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля с бензиновым двигателем, если содержание вредных веществ в отработавших газах превышает установленную величину?","a":["Нет, не разрешается.","Разрешается на автомобилях, изготовленных более чем 10 лет назад.","Разрешается на автомобилях с карбюраторной системой питания топливом.","Разрешается при использовании присадок, предназначенных для очистки системы питания топливом."],"c":0,"e":"<p>Участие в дорожном движении легкового автомобиля с повышенной токсичностью (бензиновые двигатели) или дымностью (дизельные двигатели) отработавших газов приводит к загрязнению окружающей среды и возникновению угрозы отравления участников дорожного движения.</p>","image":"assets/adrive-questions/q400102602.webp"},{"id":400102701,"themeId":6,"group":4001027,"chapter":31,"chapters":[31],"q":"Разрешается ли водителю автомобиля продолжить движение после того, как он обнаружил в пути следования подтекание из системы питания двигателя, а устранить эту неисправность не получается?","a":["Нет, не разрешается.","Разрешается, только если у автомобиля дизельный двигатель.","Разрешается только к месту стоянки или ремонта с соблюдением необходимых мер предосторожности по обеспечению безопасности дорожного движения."],"c":2,"e":"<p>Участие в дорожном движении автомобиля после того, как было обнаружено незначительное подтекание из системы питания двигателя, разрешается только при следовании к месту стоянки или ремонта с соблюдением необходимых мер предосторожности. При невозможности дальнейшего движения — доставить автомобиль к месту стоянки или ремонта с помощью специализированной технической службы. Утечка жидкого топлива из топливной системы представляет опасность из-за возможности воспламенения при соприкосновении с горячими деталями или искрой, возникшей в электрооборудовании транспортного средства.</p>","image":null},{"id":400102702,"themeId":6,"group":4001027,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении автомобиля с дизельной системой питания двигателя после того, как было обнаружено незначительное подтекание из топливного бака?","a":["Нет, не разрешается.","Да, разрешается, если топливо не попадает на разогретые детали системы выпуска отработавших газов."],"c":0,"e":"<p>Участие в дорожном движении автомобиля с дизельной системой питания двигателя после того, как было обнаружено незначительное подтекание из топливного бака, запрещается. Утечка жидкого топлива из топливной системы представляет опасность из-за возможности воспламенения при соприкосновении с горячими деталями или искрой, возникшей в электрооборудовании транспортного средства.</p>","image":null},{"id":400102801,"themeId":6,"group":4001028,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении автомобиля с прогоревшими деталями системы выпуска отработавших газов?","a":["Нет, не разрешается.","Разрешается, если шумность работы двигателя не превышает установленных предельных санитарных норм шума для территории жилой застройки."],"c":0,"e":"<p>Участие в дорожном движении автомобиля с прогоревшими деталями системы выпуска отработавших газов запрещается. Это может привести не только к увеличению шума выпуска отработавших газов, но и к попаданию их в кабину или салон транспортного средства, что может стать причиной отравления водителя и пассажиров отработанными газами.</p>","image":"assets/adrive-questions/q400102801.webp"},{"id":400102802,"themeId":6,"group":4001028,"chapter":31,"chapters":[31],"q":"Как Вы должны поступить, если при осмотре автомобиля в пути услышите повышенный шум, свидетельствующий о неисправности системы выпуска отработавших газов?","a":["Прекратите дальнейшее движение.","Проверите крепление деталей системы выпуска отработавших газов и, если крепление исправно, продолжите движение.","При невозможности устранить неисправность будете следовать к ближайшему месту ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения."],"c":2,"e":"<p>При невозможности устранить неисправность водитель должен следовать к ближайшему месту ремонта с соблюдением мер предосторожности по обеспечению безопасности дорожного движения. Неисправность системы выпуска отработавших газов может привести также к попаданию их в кабину или салон транспортного средства, что может стать причиной отравления водителя и пассажиров отработанными газами.</p>","image":"assets/adrive-questions/q400102802.webp"},{"id":400102901,"themeId":6,"group":4001029,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей систем двигателя запрещается участие автомобиля в дорожном движении?","a":["Подтекает жидкость из системы охлаждения двигателя.","Неисправна система охлаждения двигателя, двигатель перегревается.","Негерметично соединение топливопровода, имеется подтекание топлива.","Подтекает моторное масло, негерметично уплотнение подшипника коленчатого вала.","При любой из перечисленных неисправностей участие в дорожном движении запрещено."],"c":2,"e":"<p>Из перечисленных неисправностей систем двигателя запрещается участие автомобиля в дорожном движении при негерметичном соединении топливопровода и если имеется подтекание топлива. Утечка жидкого топлива из топливной системы представляет опасность из-за возможности воспламенения при соприкосновении с горячими деталями или из-за искры, возникшей в электрооборудовании транспортного средства. Приведённые другие неисправности не влияют напрямую на безопасность дорожного движения и не могут стать причиной создания аварийной ситуации на дороге и ДТП.</p>","image":null},{"id":400102902,"themeId":6,"group":4001029,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей систем двигателя запрещается участие автомобиля в дорожном движении?","a":["Затруднён запуск двигателя, аккумулятор разряжен.","Засорен воздушный фильтр системы питания двигателя воздухом.","Нарушен угол опережения зажигания, двигатель работает с перебоями.","После наезда на препятствие имеется повреждение деталей системы выпуска отработавших газов, некоторое их количество не проходит через глушитель.","При любой из перечисленных неисправностей участие в дорожном движении запрещено."],"c":3,"e":"<p>Участие в дорожном движении автомобиля с неисправностями системы выпуска отработавших газов запрещается. Это может привести не только к увеличению шума выпуска отработавших газов, но и к попаданию их в кабину или салон транспортного средства, что может стать причиной отравления водителя и пассажиров отработанными газами.</p>","image":null},{"id":400102951,"themeId":6,"group":4001029,"chapter":31,"chapters":[31],"q":"Разрешено ли водителю, обнаружившему в пути  подтекание жидкости из системы охлаждения двигателя, продолжить намеченную поездку, если устранить неисправность нет возможности?","a":["Нет, необходимо прекратить дальнейшее движение.","Нет, необходимо двигаться к месту стоянки или ремонта с соблюдением необходимых мер по обеспечению безопасности дорожного движения.","Да, разрешено, периодически доливая жидкость и не допуская перегрева двигателя."],"c":2,"e":"<p>Правилами дорожного движение запрещено участие в движении транспортного средства с негерметичной системой питания двигателя (топливной системой). <strong>Запретов на участие в дорожном движении транспортного средства, имеющего подтекание из системы охлаждения в ПДД нет</strong>.</p>","image":"assets/adrive-questions/q400102951.webp"},{"id":400103101,"themeId":6,"group":4001031,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей запрещается участие автомобиля в дорожном движении?","a":["Первая передача включается с затруднением.","Изношен подшипник ступицы заднего колеса.","Автомобиль медленно разгоняется. Сцепление буксует.","Негерметична газовая система питания на транспортном средстве с газовой топливной аппаратурой.","При любой из перечисленных неисправностей участие в дорожном движении запрещено."],"c":3,"e":"<p>Из перечисленных неисправностей запрещается участие автомобиля в дорожном движении, если нарушена герметичность газовой системы питания на транспортном средстве с газовой топливной аппаратурой, в связи с тем, что данная неисправность может привести к самовозгоранию или взрыву транспортного средства.</p>","image":null},{"id":400103102,"themeId":6,"group":4001031,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей запрещается участие автомобиля в дорожном движении?","a":["Нарушена герметичность системы питания.","Неисправна система выпуска отработавших газов. Прогорел глушитель.","Истек срок периодического освидетельствования баллонов на газобаллонных транспортных средствах.","Дымность отработавших газов превышает величину, установленную техническими нормативными правовыми актами.","При любой из перечисленных неисправностей участие в дорожном движении запрещено."],"c":4,"e":"<p>При любой из перечисленных неисправностей участие в дорожном движении запрещается, так как данные неисправности напрямую влияют на безопасность дорожного движения или ведут к повышенному загрязнению окружающей среды.</p>","image":null},{"id":400103201,"themeId":6,"group":4001032,"chapter":31,"chapters":[31],"q":"Как должен поступить водитель, если в пути он обнаружил неисправность звукового сигнала, а устранить неисправность своими силами не представляется возможным?","a":["Прекратить дальнейшее движение.","Продолжать движение, используя световой сигнал в качестве предупредительного.","Двигаться к месту стоянки или ремонта, соблюдая необходимые меры предосторожности по обеспечению безопасности дорожного движения."],"c":2,"e":"<p>Из перечисленных неисправностей запрещается участие автомобиля в дорожном движении при неисправном звуковом сигнале. В связи с этим обстоятельством, если водитель не может устранить неисправность самостоятельно, он обязан двигаться к месту стоянки или ремонта, соблюдая необходимые меры предосторожности по обеспечению безопасности дорожного движения.</p>","image":"assets/adrive-questions/q400103201.webp"},{"id":400103202,"themeId":6,"group":4001032,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении автомобиля, у которого не работает звуковой сигнал?","a":["Нет, не разрешается.","Разрешается только при движении в населённом пункте.","Разрешается, если исправны внешние световые приборы."],"c":0,"e":"<p>Так как звуковой сигнал может применяться для предотвращения ДТП, Правила дорожного движения запрещают участие легкового автомобиля в дорожном движении при неисправном звуковом сигнале.</p>","image":null},{"id":400103302,"themeId":6,"group":4001033,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей запрещается участие легкового автомобиля в дорожном движении?","a":["Не работает звуковой сигнал.","Негерметичен амортизатор подвески.","Негерметична система смазки двигателя.","Истек срок замены масла в системе смазки двигателя.","При любой из перечисленных неисправностей участие в дорожном движении запрещено."],"c":0,"e":"<p>Так как звуковой сигнал может применяться для предотвращения ДТП, Правила дорожного движения запрещают участие легкового автомобиля в дорожном движении при неисправном звуковом сигнале.</p>","image":null},{"id":400103401,"themeId":6,"group":4001034,"chapter":31,"chapters":[31],"q":"Разрешается ли устанавливать шторки на стёклах легкового автомобиля, не предусмотренные его конструкцией?","a":["Нет, не разрешается.","Да, разрешается на боковые (кроме передних) стёкла и заднее стекло при наличии у автомобиля с обеих сторон наружных зеркал заднего вида.","Разрешается только на заднее стекло при наличии у автомобиля с обеих сторон наружных зеркал заднего вида."],"c":1,"e":"<p>Допускается применять шторки на задних и боковых (кроме передних) стёклах легковых автомобилей только при наличии с обеих сторон наружных зеркал заднего вида, в связи с тем, что шторки несущественно ограничивают водителю обзорность дороги и создают комфортные условия для перевозки пассажиров.</p>","image":"assets/adrive-questions/q400103401.webp"},{"id":400103402,"themeId":6,"group":4001034,"chapter":31,"chapters":[31],"q":"Разрешается ли устанавливать жалюзи на стёклах легкового автомобиля, не предусмотренные его конструкцией?","a":["Нет, не разрешается.","Да, разрешается на боковые (кроме передних) стёкла и заднее стекло при наличии у автомобиля с обеих сторон наружных зеркал заднего вида.","Да, разрешается, но запрещается закрывать их полностью.","Разрешается только на заднее стекло при наличии у автомобиля с обеих сторон наружных зеркал заднего вида."],"c":1,"e":"<p>Допускается применять жалюзи или шторки на боковых (кроме передних) и заднем стеклах легкового автомобиля при наличии с обеих сторон наружных зеркал заднего вида в связи с тем, что шторки несущественно ограничивают водителю обзорность дороги и создают комфортные условия для перевозки пассажиров.</p>","image":null},{"id":400103531,"themeId":6,"group":4001035,"chapter":31,"chapters":[31],"q":"Разрешается ли участие в дорожном движении легкового автомобиля с нанесённой на верхнюю часть ветрового стекла светозащитной полосой в виде прозрачной цветной пленки?","a":["Нет, не разрешается.","Разрешается, если её ширина не превышает 140 мм.","Разрешается, если стекло имеет степень светопропускания не менее 70%."],"c":1,"e":"<p>Максимальная ширина цветной плёнки, нанесённой на верхнюю часть ветрового стекла, допускается не более 140 мм. Данные плёнки, светозащитные полосы, выполненные в массе стекла, применяются против ослепляющего действия во время движения в ясную солнечную погоду.</p>","image":"assets/adrive-questions/q400103531.webp"},{"id":400103532,"themeId":6,"group":4001035,"chapter":31,"chapters":[31],"q":"Какая максимальная ширина светозащитной полосы в виде прозрачной цветной пленки, нанесённой на верхнюю часть ветрового стекла, допускается для участия в дорожном движении?","a":["100 мм.","120 мм.","140 мм.","160 мм.","180 мм."],"c":2,"e":"<p>Максимальная ширина цветной плёнки, нанесённой на верхнюю часть ветрового стекла, допускается не более 140 мм. Данные плёнки, светозащитные полосы, выполненные в массе стекла, применяются против ослепляющего действия во время движения в ясную солнечную погоду.</p>","image":"assets/adrive-questions/q400103532.webp"},{"id":400103541,"themeId":6,"group":4001035,"chapter":31,"chapters":[31],"q":"Допускается ли участие в дорожном движении автомобиля с установленным видеорегистратором?","a":["Не допускается, если он ограничивает обзорность с места водителя.","Не допускается, если он ограничивает обзорность с места пассажира.","Не допускается в обоих перечисленных случаях."],"c":0,"e":"<p>Допускаются установка и наличие на транспортном средстве средств регистрации и записи окружающей обстановки (видеорегистратор), не ограничивающих обзорность с места водителя.</p>","image":"assets/adrive-questions/q400103541.webp"},{"id":400103602,"themeId":6,"group":4001036,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля?","a":["Не включается вентилятор системы охлаждения двигателя.","У колёс передней и задней оси отличается рисунок протектора шин.","Уровень масла в системе смазки двигателя — на минимальной отметке щупа.","На передние боковые стёкла нанесены не предусмотренные конструкцией плёночные покрытия при наличии с обеих сторон наружных зеркал заднего вида."],"c":3,"e":"<p>Из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля только если <strong>на передние боковые стёкла нанесены плёночные покрытия, не предусмотренные конструкцией</strong>, так как они ухудшают светопропускание стекла и ограничивают обзорность дороги, затрудняя управление автомобилем.</p> <p>Приведённые другие неисправности не влияют напрямую на безопасность дорожного движения и не могут стать причиной создания аварийной ситуации на дороге и ДТП.</p>","image":null},{"id":400103631,"themeId":6,"group":4001036,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля?","a":["Не работает плафон освещения салона.","Двигатель работает неустойчиво на холостых оборотах.","Не работает указатель уровня топлива в топливном баке.","На заднем стекле имеется трещина в зоне, очищаемой стеклоочистителем.","На передние боковые стёкла нанесены не предусмотренные конструкцией плёночные покрытия."],"c":4,"e":"<p>Из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля только если на его передние боковые стёкла нанесены не предусмотренные конструкцией покрытия, в том числе плёночные, так как они ухудшают светопропускание стёкол и ограничивают обзорность дороги, затрудняя управление автомобилем.</p>","image":null},{"id":400103801,"themeId":6,"group":4001038,"chapter":31,"chapters":[31],"q":"Разрешается ли участвовать в дорожном движении автомобилю с неработающим спидометром?","a":["Нет, не разрешается.","Разрешается, если есть тахометр.","Разрешается при движении с небольшой скоростью по дорогам без усовершенствованного покрытия."],"c":0,"e":"<p>Из перечисленных неисправностей автомобиля запрещается участие в дорожном движении, если спидометр не находится в работоспособном состоянии, так как он должен обеспечивать водителю необходимый контроль за скоростным режимом движения.</p>","image":"assets/adrive-questions/q400103801.webp"},{"id":400103802,"themeId":6,"group":4001038,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей автомобиля запрещается участие в дорожном движении?","a":["Не работает спидометр.","Не работает прикуриватель.","Не работает плафон освещения салона.","Не работает подсветка панели приборов.","Не работает датчик температуры охлаждающей жидкости."],"c":0,"e":"<p>Из перечисленных неисправностей автомобиля запрещается участие в дорожном движении, если спидометр не находится в работоспособном состоянии, так как он должен обеспечивать водителю необходимый контроль за скоростным режимом движения.</p>","image":null},{"id":400103851,"themeId":6,"group":4001038,"chapter":31,"chapters":[31],"q":"Как следует поступить водителю легкового автомобиля, если в пути перестал работать спидометр, а устранить эту неисправность нет возможности?","a":["Прекратить дальнейшее движение.","Следовать к месту стоянки или ремонта, включив аварийную световую сигнализацию, соблюдая необходимые меры предосторожности по обеспечению безопасности дорожного движения."],"c":1,"e":"<p>Если не работает спидометр, и устранить неисправность в пути нет возможности, водитель может <strong>следовать к месту стоянки или ремонта</strong> с соблюдением необходимых мер предосторожности.</p>","image":"assets/adrive-questions/q400103851.webp"},{"id":400103901,"themeId":6,"group":4001039,"chapter":31,"chapters":[31],"q":"Разрешается ли участвовать в дорожном движении автомобилю с неработающим устройством обогрева и обдува стёкол?","a":["Нет, не разрешается.","Разрешается в весенне-летний период эксплуатации."],"c":0,"e":"<p>Предусмотренные конструкцией механического ТС устройства обдува и обогрева стёкол должны быть в работоспособном состоянии. Устройства для обогрева и обдува стекла предназначены для увеличения циркуляции воздуха и способствуют предотвращению обмерзания (запотевания) стёкол.</p>","image":"assets/adrive-questions/q400103901.webp"},{"id":400103902,"themeId":6,"group":4001039,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей разрешается участие в дорожном движении легкового автомобиля?","a":["Неисправно устройство обогрева заднего стекла.","Неисправно устройство обогрева наружных зеркал заднего вида.","Неисправно устройство обдува ветрового и передних боковых стёкол.","Участие в дорожном движении запрещено при любой из перечисленных неисправностей."],"c":1,"e":"<p>Из перечисленных неисправностей разрешается участие в дорожном движении легкового автомобиля при неисправностях устройства обогрева наружных зеркал заднего вида. Приведённые другие неисправности влияют напрямую на безопасность дорожного движения и могут стать причиной создания аварийной ситуации на дороге и ДТП.</p>","image":null},{"id":400104001,"themeId":6,"group":4001040,"chapter":31,"chapters":[31],"q":"Без какого оборудования из перечисленного ниже запрещается легковому автомобилю участвовать в дорожном движении?","a":["Домкрат.","Огнетушитель.","Буксировочный трос.","Ключ для замены колеса.","Без всего перечисленного выше Правила дорожного движения запрещают участвовать в дорожном движении."],"c":1,"e":"<p>Из комплектации по Правилам дорожного движения легковому автомобилю при отсутствии огнетушителя участие в дорожном движении запрещено, так как огнетушитель необходим для тушения пожара в случае возгорания транспортных средств.</p>","image":"assets/adrive-questions/q400104001.webp"},{"id":400104002,"themeId":6,"group":4001040,"chapter":31,"chapters":[31],"q":"Какое оборудование из перечисленного ниже обязательно должно быть в наличии в легковом автомобиле для участия в дорожном движении?","a":["Огнетушитель.","Медицинская аптечка и знак аварийной остановки.","Все перечисленные предметы должны быть в наличии."],"c":2,"e":"<p>Легковой автомобиль для участия в дорожном движении должен быть оснащен огнетушителем, медицинской аптечкой и знаком аварийной остановки.</p> <p>Медицинская аптечка необходима для оказания первой медицинской помощи, знак аварийной остановки выставляется для предупреждения об опасности, огнетушитель необходим для тушения пожара в случае возгорания транспортных средств.</p>","image":"assets/adrive-questions/q400104002.webp"},{"id":400104041,"themeId":6,"group":4001040,"chapter":31,"chapters":[31],"q":"Легковые автомобили оснащаются огнетушителем:","a":["Ёмкостью не менее 0.5 литра.","Ёмкостью не менее 1 литра.","Ёмкостью не менее 2 литров."],"c":1,"e":"<p>Легковые автомобили оснащаются не менее чем одним огнетушителем ёмкостью не менее 1 литра. Огнетушитель размещается в легкодоступном месте.</p> <p>Огнетушители должны быть опломбированы, и на них должен быть указан срок окончания использования, который на момент проверки не должен быть завершён.</p>","image":null},{"id":400104101,"themeId":6,"group":4001041,"chapter":31,"chapters":[31],"q":"Без какого оборудования из перечисленного ниже грузовому автомобилю с технически допустимой общей массой до 3.5 тонны запрещается участвовать в дорожном движении?","a":["Без медицинской аптечки.","Без противооткатных упоров.","Без жёсткого буксирующего устройства, соответствующего требованиям технических нормативных правовых актов.","Без всего перечисленного выше Правила дорожного движения запрещают участвовать в дорожном движении."],"c":0,"e":"<p>Из перечисленных вариантов грузовому автомобилю с технически допустимой общей массой до 3.5 тонны участие в дорожном движении запрещается при отсутствии медицинской аптечки, так как медицинская аптечка необходима для оказания первой медицинской помощи пострадавшим при ДТП.</p>","image":"assets/adrive-questions/q400104101.webp"},{"id":400104201,"themeId":6,"group":4001042,"chapter":31,"chapters":[31],"q":"Что из нижеперечисленного не требуется для участия в дорожном движении легковому автомобилю с прицепом?","a":["Огнетушитель.","Медицинская аптечка.","Противооткатные упоры.","Знак аварийной остановки.","Для участия в дорожном движении требуется всё вышеперечисленное."],"c":2,"e":"<p>Для участия в дорожном движении легковому автомобилю с прицепом из перечисленного не требуются только противооткатные упоры.</p> <p>Медицинская аптечка необходима для оказания первой медицинской помощи, знак аварийной остановки выставляется для предупреждения об опасности, огнетушитель — для тушения пожара в случае возгорания транспортных средств.</p>","image":"assets/adrive-questions/q400104201.webp"},{"id":400104202,"themeId":6,"group":4001042,"chapter":31,"chapters":[31],"q":"Что из нижеперечисленного не требуется для участия в дорожном движении грузовому автомобилю с технически допустимой общей массой до 3.5 тонны?","a":["Огнетушитель.","Медицинская аптечка.","Противооткатные упоры.","Знак аварийной остановки.","Для участия в дорожном движении требуется всё вышеперечисленное."],"c":2,"e":"<p>Для участия в дорожном движении грузовому автомобилю с технически допустимой общей массой до 3.5 тонны не требуются только противооткатные упоры.</p> <p>Медицинская аптечка необходима для оказания первой медицинской помощи, знак аварийной остановки выставляется для предупреждения об опасности, огнетушитель — для тушения пожара в случае возгорания транспортных средств.</p>","image":"assets/adrive-questions/q400104202.webp"},{"id":400104302,"themeId":6,"group":4001043,"chapter":31,"chapters":[31],"q":"Какое транспортное средство может участвовать в дорожном движении без огнетушителя?","a":["Только мотоцикл с боковым прицепом.","Только мотоцикл без бокового прицепа.","Все перечисленные транспортные средства."],"c":2,"e":"<p>К транспортным средствам, которые могут участвовать в дорожном движении без огнетушителя, относятся мотоциклы, как с боковым прицепом, так и без него.</p>","image":null},{"id":400104401,"themeId":6,"group":4001044,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев грузовой автомобиль с технически допустимой общей массой до 3.5 тонны не должен быть допущен к участию в дорожном движении?","a":["Отсутствуют противооткатные упоры.","Запасное колесо имеет сквозное повреждение (пробой).","Отсутствует предусмотренный конструкцией грязезащитный фартук.","В любом из перечисленных случаев грузовой автомобиль не должен быть допущен к участию в дорожном движении."],"c":2,"e":"<p>Для предупреждения загрязнения ветрового (лобового) и заднего стёкол, а также для защиты ТС от попадания грязи, камней и тому подобного из-под колёс других ТС, на них должны быть установлены грязезащитные фартуки и брызговики.</p>","image":null},{"id":400104402,"themeId":6,"group":4001044,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев грузовой автомобиль с технически допустимой общей массой до 3.5 тонны может быть допущен к участию в дорожном движении?","a":["Отсутствует медицинская аптечка.","Отсутствуют противооткатные упоры.","Отсутствует предусмотренное конструкцией запасное колесо.","В любом из перечисленных случаев грузовой автомобиль не должен быть допущен к участию в дорожном движении."],"c":1,"e":"<p>Грузовой автомобиль с технически допустимой общей массой до 3.5 тонны может быть допущен к участию в дорожном движении при отсутствии противооткатных упоров, медицинская аптечка необходима для оказания первой медицинской помощи, а запасное колесо предусмотрено конструкцией транспортного средства и должно быть всегда в наличии.</p>","image":"assets/adrive-questions/q400104402.webp"},{"id":400104501,"themeId":6,"group":4001045,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев грузовой автомобиль с технически допустимой общей массой до 3.5 тонны не должен быть допущен к участию в дорожном движении?","a":["Отсутствуют противооткатные упоры.","В бачок стеклоомывателей заправлена вода.","Отсутствуют предусмотренные конструкцией ремни безопасности.","В любом из перечисленных случаев грузовой автомобиль не должен быть допущен к участию в дорожном движении."],"c":2,"e":"<p>Из перечисленных случаев грузовой автомобиль с технически допустимой общей массой до 3.5 тонны не должен быть допущен к участию в дорожном движении без предусмотренных конструкцией ремней безопасности.</p>","image":"assets/adrive-questions/q400104501.webp"},{"id":400104502,"themeId":6,"group":4001045,"chapter":31,"chapters":[31],"q":"При какой из перечисленных неисправностей грузовой автомобиль с технически допустимой общей массой до 3.5 тонны не может быть допущен к участию в дорожном движении?","a":["Повышенный шум шестерен редуктора заднего моста.","Имеются незначительные внешние повреждения деталей кузова.","Не работает механизм регулировки положения сиденья водителя.","В любом из перечисленных случаев грузовой автомобиль не должен быть допущен к участию в дорожном движении."],"c":2,"e":"<p>Грузовой автомобиль с технически допустимой общей массой до 3.5 тонны при неработающем механизме регулировки положения сиденья водителя не может быть допущен к участию в дорожном движении. Неудобное расположение на рабочем месте может привести к быстрой утомляемости водителя и к созданию предпосылок для возникновения ДТП.</p>","image":null},{"id":400104601,"themeId":6,"group":4001046,"chapter":31,"chapters":[31],"q":"Мотоцикл без бокового прицепа не должен быть допущен к участию в дорожном движении:","a":["При отсутствии огнетушителя.","При отсутствии медицинской аптечки.","При неисправности рулевого демпфера.","При отсутствии знака аварийной остановки."],"c":2,"e":"<p>Рулевой демпфер на мотоцикле должен быть в наличии, если это предусмотрено конструкцией, и быть в исправном состоянии. Работа данного элемента рулевого управления направлена на сохранение управляемости мотоцикла, что достигается за счёт гашения колебаний, возникающих в процессе движения в рулевом управлении.</p>","image":"assets/adrive-questions/q400104601.webp"},{"id":400104602,"themeId":6,"group":4001046,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев мотоцикл без бокового прицепа может быть допущен к участию в дорожном движении?","a":["Неисправен рулевой демпфер.","Отсутствует медицинская аптечка.","Неисправна система выпуска отработавших газов.","Нарушена герметичность системы питания двигателя.","В любом из перечисленных случаев мотоцикл не должен быть допущен к участию в дорожном движении."],"c":1,"e":"<p>Наличие медицинской аптечки не входит в обязательный перечень комплектации мотоцикла без бокового прицепа.</p>","image":"assets/adrive-questions/q400104602.webp"},{"id":400104701,"themeId":6,"group":4001047,"chapter":31,"chapters":[31],"q":"Мотоцикл с боковым прицепом может быть допущен к участию в дорожном движении:","a":["При отсутствии огнетушителя.","При отсутствии медицинской аптечки.","При неисправности рулевого демпфера.","При отсутствии знака аварийной остановки."],"c":0,"e":"<p>Наличие огнетушителя не входит в обязательный перечень комплектации мотоцикла с боковым прицепом.</p>","image":"assets/adrive-questions/q400104701.webp"},{"id":400104702,"themeId":6,"group":4001047,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев мотоцикл с боковым прицепом может быть допущен к участию в дорожном движении?","a":["Отсутствует огнетушитель.","Неисправен рулевой демпфер.","Нарушена герметичность системы питания двигателя.","Установлены дополнительные элементы системы выпуска отработавших газов без согласования с изготовителем.","В любом из перечисленных случаев мотоцикл не должен быть допущен к участию в дорожном движении."],"c":0,"e":"<p>Наличие огнетушителя не входит в обязательный перечень комплектации мотоцикла с боковым прицепом.</p>","image":null},{"id":400104801,"themeId":6,"group":4001048,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля?","a":["Имеются незначительные внешние повреждения деталей кузова.","Имеются незначительные внешние повреждения окраски автомобиля.","Окраска автомобиля не соответствует указанной в свидетельстве о регистрации транспортного средства.","В любом из перечисленных случаев легковому автомобилю не разрешается участвовать в дорожном движении."],"c":2,"e":"<p>Согласно Правилам дорожного движения, легковой автомобиль со значительными внешними повреждениями окраски и деталей кузова, а также, если окраска автомобиля не соответствует указанной в свидетельстве о регистрации транспортного средства, не допускается к участию в дорожном движении. Под значительными внешними повреждениями деталей кузова и окраски автомобиля понимаются повреждения, обуславливающие его неприглядный внешний вид и выделяющие его в транспортном потоке.</p>","image":null},{"id":400104802,"themeId":6,"group":4001048,"chapter":31,"chapters":[31],"q":"В каком из перечисленных случаев не разрешается участие в дорожном движении легкового автомобиля?","a":["Имеются значительные внешние повреждения деталей кузова.","Имеются значительные внешние повреждения окраски автомобиля.","Окраска автомобиля не соответствует указанной в свидетельстве о регистрации транспортного средства.","В любом из перечисленных случаев легковому автомобилю не разрешается участвовать в дорожном движении."],"c":3,"e":"<p>Согласно Правилам дорожного движения легковой автомобиль со значительными внешними повреждениями окраски и деталей кузова, а также, если окраска автомобиля не соответствует указанной в свидетельстве о регистрации транспортного средства, не допускается к участию в дорожном движении. Под значительными внешними повреждениями деталей кузова и окраски автомобиля понимаются повреждения, обуславливающие его неприглядный внешний вид и выделяющие его в транспортном потоке.</p>","image":"assets/adrive-questions/q400104802.webp"}];